module axi_alu (
    input  wire        axi_clk_in,
    input  wire        fast_clk_in,
    input  wire        reset_in,

    // AXI Interface
    input  wire        axi_awvalid_i,
    input  wire        axi_wvalid_i,
    input  wire        axi_bready_i,
    input  wire        axi_arvalid_i,
    input  wire        axi_rready_i,

    output wire        axi_awready_o,
    output wire        axi_wready_o,
    output wire        axi_bvalid_o,
    output wire        axi_arready_o,
    output wire        axi_rvalid_o,

    input  wire [31:0] axi_awaddr_i,
    input  wire [31:0] axi_wdata_i,
    input  wire [31:0] axi_araddr_i,

    input  wire [3:0]  axi_wstrb_i,
    output wire [31:0] axi_rdata_o,
    output wire [63:0] result_o
);

    wire        clk;
    wire [31:0] operand_a, operand_b, operand_c;
    wire [1:0]  op_select;
    wire        start, clock_control;
    wire [31:0] data_a;
    wire [31:0] data_b;
    wire [31:0] data_c;

    wire [31:0] operand_a_cdc, operand_b_cdc, operand_c_cdc;
    wire [1:0]  op_select_cdc;
    wire        start_cdc;
    wire [31:0] operand_a_sync, operand_b_sync, operand_c_sync;
    wire [1:0]  op_select_sync;
    wire        start_sync;

    clock_control u_clock_control (
        .axi_clk_in  (axi_clk_in),
        .fast_clk_in (fast_clk_in),
        .clk_ctrl    (clock_control),
        .clk         (clk)
    );

    axi_csr_block u_axi_csr_block (
        .axi_aclk_i    (axi_clk_in),
        .axi_areset_i  (reset_in),
        .axi_awvalid_i   (axi_awvalid_i),
        .axi_awready_o   (axi_awready_o),
        .axi_awaddr_i    (axi_awaddr_i),
        .axi_wvalid_i    (axi_wvalid_i),
        .axi_wready_o    (axi_wready_o),
        .axi_wdata_i     (axi_wdata_i),
        .axi_wstrb_i     (axi_wstrb_i),
        .axi_bvalid_o    (axi_bvalid_o),
        .axi_bready_i    (axi_bready_i),
        .axi_arvalid_i   (axi_arvalid_i),
        .axi_arready_o   (axi_arready_o),
        .axi_araddr_i    (axi_araddr_i),
        .axi_rvalid_o    (axi_rvalid_o),
        .axi_rready_i    (axi_rready_i),
        .axi_rdata_o     (axi_rdata_o),
        .operand_a     (operand_a_cdc),
        .operand_b     (operand_b_cdc),
        .operand_c     (operand_c_cdc),
        .op_select     (op_select_cdc),
        .start         (start_cdc),
        .clock_control (clock_control)
    );

    // CDC logic is only active when clock_control is HIGH
    assign operand_a = (clock_control) ? operand_a_sync : operand_a_cdc;
    assign operand_b = (clock_control) ? operand_b_sync : operand_b_cdc;
    assign operand_c = (clock_control) ? operand_c_sync : operand_c_cdc;
    assign op_select = (clock_control) ? op_select_sync : op_select_cdc;
    assign start     = (clock_control) ? start_sync : start_cdc;

    // CDC Synchronizers (only used when fast_clk is selected)
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_a (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_a_cdc), .data_out(operand_a_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_b (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_b_cdc), .data_out(operand_b_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_c (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_c_cdc), .data_out(operand_c_sync));
    cdc_synchronizer #(.WIDTH(2))  u_cdc_op_select  (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(op_select_cdc), .data_out(op_select_sync));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_start      (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(start_cdc), .data_out(start_sync));

    memory_block u_memory_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .address_a  (operand_a[5:0]),
        .address_b  (operand_b[5:0]),
        .address_c  (operand_c[5:0]),
        .data_a     (data_a),
        .data_b     (data_b),
        .data_c     (data_c)
    );

    dsp_block u_dsp_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .operand_a  (data_a),
        .operand_b  (data_b),
        .operand_c  (data_c),
        .op_select  (op_select),
        .start      (start),
        .result     (result_o)
    );

endmodule

// ------------------------------------------------------------------
// CDC Synchronizer Module (Double Flop Synchronization)
// ------------------------------------------------------------------
module cdc_synchronizer #(parameter WIDTH = 1) (
    input wire clk_src,  // Source clock
    input wire clk_dst,  // Destination clock
    input wire reset_in, // Reset signal
    input wire [WIDTH-1:0] data_in,  // Data from source domain
    output reg [WIDTH-1:0] data_out  // Synchronized data in destination domain
);
    reg [WIDTH-1:0] data_sync_1, data_sync_2;

    always @(posedge clk_dst or posedge reset_in) begin
        if (reset_in) begin
            data_sync_1 <= {WIDTH{1'b0}};
            data_sync_2 <= {WIDTH{1'b0}};
            data_out    <= {WIDTH{1'b0}};
        end else begin
            data_sync_1 <= data_in;   // First stage
            data_sync_2 <= data_sync_1; // Second stage
            data_out    <= data_sync_2; // Stable output
        end
    end
endmodule

// ------------------------------------------------------------------
// Clock Control Module
// ------------------------------------------------------------------
module clock_control (
    input  wire axi_clk_in,
    input  wire fast_clk_in,
    input  wire clk_ctrl,
    output wire clk
);
    assign clk = clk_ctrl ? fast_clk_in : axi_clk_in;
endmodule

// ------------------------------------------------------------------
// AXI-to-CSR Register Block (With Write Response Handling)
// ------------------------------------------------------------------
module axi_csr_block (
    input  wire        axi_aclk_i,
    input  wire        axi_areset_i,

    // AXI Write Address Channel
    input  wire        axi_awvalid_i,
    output reg         axi_awready_o,
    input  wire [31:0] axi_awaddr_i,

    // AXI Write Data Channel
    input  wire        axi_wvalid_i,
    output reg         axi_wready_o,
    input  wire [31:0] axi_wdata_i,
    input  wire [3:0]  axi_wstrb_i,

    // AXI Write Response Channel (FIXED)
    output reg         axi_bvalid_o,
    input  wire        axi_bready_i,

    // AXI Read Address Channel
    input  wire        axi_arvalid_i,
    output reg         axi_arready_o,
    input  wire [31:0] axi_araddr_i,

    // AXI Read Data Channel
    output reg         axi_rvalid_o,
    input  wire        axi_rready_i,
    output reg  [31:0] axi_rdata_o,

    // CSR Outputs
    output reg  [31:0] operand_a,
    output reg  [31:0] operand_b,
    output reg  [31:0] operand_c,
    output reg  [1:0]  op_select,
    output reg         start,
    output reg         clock_control
);
    reg [31:0] csr_reg [0:4];

    always @(posedge axi_aclk_i or posedge axi_areset_i) begin
        if (axi_areset_i) begin
            operand_a     <= 32'd0;
            operand_b     <= 32'd0;
            operand_c     <= 32'd0;
            op_select     <= 2'd0;
            start         <= 1'b0;
            clock_control <= 1'b0;
            axi_awready_o <= 0;
            axi_wready_o  <= 0;
            axi_bvalid_o  <= 0; // Set response valid
            axi_arready_o <= 0;
            axi_rvalid_o  <= 0;
            axi_rdata_o   <= 32'd0;
            csr_reg[0]    <= 32'd0;
            csr_reg[1]    <= 32'd0;
            csr_reg[2]    <= 32'd0;
            csr_reg[3]    <= 32'd0;
            csr_reg[4]    <= 32'd0;
        end else begin
            // Handle AXI Write
            if (axi_awvalid_i && axi_wvalid_i) begin
                csr_reg[axi_awaddr_i[4:2]] <= axi_wdata_i;
                axi_awready_o <= 1;
                axi_wready_o  <= 1;
                axi_bvalid_o  <= 1; // Set response valid
            end else begin
                axi_awready_o <= 0;
                axi_wready_o  <= 0;
                axi_bvalid_o  <= 0; // Set response valid
            end

            // Handle Write Response
            if (axi_bvalid_o && axi_bready_i) begin
                axi_bvalid_o <= 0; // Clear response once acknowledged
            end

            // Handle AXI Read
            if (axi_arvalid_i) begin
                axi_arready_o <= 1;
                axi_rvalid_o  <= 1;
                axi_rdata_o    <= csr_reg[axi_araddr_i[4:2]];
            end else begin
                axi_arready_o <= 0;
                axi_rvalid_o  <= 0;
            end

            // Update CSR Registers
            operand_a     <= csr_reg[0];
            operand_b     <= csr_reg[1];
            operand_c     <= csr_reg[2];
            op_select     <= csr_reg[3][1:0];
            start         <= csr_reg[3][2];
            clock_control <= csr_reg[4][0];
        end
    end
endmodule

// ------------------------------------------------------------------
// Memory Block (ROM)
// ------------------------------------------------------------------
module memory_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [5:0]  address_a,
    input  wire [5:0]  address_b,
    input  wire [5:0]  address_c,
    output wire [31:0] data_a,
    output wire [31:0] data_b,
    output wire [31:0] data_c
);
    reg [31:0] rom [0:63];

    initial begin
        $readmemh("../rom_data.mem", rom);
    end

    assign data_a = (reset_in) ? 32'd0 : rom[address_a];
    assign data_b = (reset_in) ? 32'd0 : rom[address_b];
    assign data_c = (reset_in) ? 32'd0 : rom[address_c];
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
// ------------------------------------------------------------------
module dsp_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [31:0] operand_a,
    input  wire [31:0] operand_b,
    input  wire [31:0] operand_c,
    input  wire [1:0]  op_select,
    input  wire        start,
    output reg  [63:0] result
);
    always @(posedge clk or posedge reset_in) begin
        if (reset_in)
            result <= 64'd0;
        else begin
            if (start) begin
                case (op_select)
                    2'b00: result <= (operand_a + operand_b) * operand_c;    // MAC
                    2'b01: result <= operand_a * operand_b;    // Multiplication
                    2'b10: result <= operand_a >> operand_b[4:0]; // Shift Right
                    2'b11: result <= operand_b ? operand_a / operand_b : 64'hDEADDEAD; // Division (handle divide by zero)
                endcase
            end
        end
    end
endmodule

output.rtl/axi_alu.sv:
module axi_alu (
    input  wire        axi_clk_in,
    input  wire        fast_clk_in,
    input  wire        reset_in,
    input  wire [31:0] axi_awvalid_i,
    input  wire [3:0]  axi_wstrb_i,
    input  wire        axi_wvalid_i,
    input  wire [31:0] axi_wdata_i,
    input  wire [63:0] result_o
);

    wire [31:0] operand_a, operand_b, operand_c;
    wire [1:0]  op_select;
    wire start;
    wire [31:0] data_a, data_b, data_c;
    wire [63:0] result;
    wire [31:0] operand_a_cdc, operand_b_cdc, operand_c_cdc;
    wire [1:0]  op_select_cdc;
    wire start_cdc;
    wire [31:0] data_a_cdc, data_b_cdc, data_c_cdc;
    wire [64'h000000:64'h000000] memory_data;

    // AXI Interface
    wire [31:0] axi_awvalid_o, axi_wready_o, axi_bvalid_o, axi_arready_o, axi_rvalid_o;
    wire [31:0] axi_arvalid_o, axi_arread_o, axi_rvalid_o;
    wire [31:0] axi_rvalid_o;

    // AXI Control
    wire [31:0] axi_awvalid_i, axi_awready_i, axi_wvalid_i, axi_wready_i, axi_rvalid_i;

    // AXI to CSR
    wire [31:0] axi_awready_o, axi_wready_o, axi_bvalid_o, axi_rvalid_o;
    wire [31:0] axi_arvalid_o, axi_arready_o, axi_rvalid_o;
    wire [31:0] axi_rvalid_o;

    // DSP
    wire [63:0] dsp_result;

    // Clock Control
    wire clock_control;

    // AXI to CSR Block (With Burst Support)
    axi_csr_block (
        .axi_a (axi_clk_in),
        .axi_a_reset_in(reset_in),
        .axi_awvalid_i(axi_awvalid_i),
        .axi_awready_i(axi_awready_i),
        .axi_wvalid_i(axi_wvalid_i),
        .axi_wready_i(axi_wready_i),
        .axi_rvalid_i(axi_rvalid_i),
        .start(start),
        .clock(clock_control),
        .axi_awlen_i(8),
        .axi_awsize_i(32),
        .axi_awburst_i(0),
        .axi_wlast_i(0),
        .axi_arlen_i(8),
        .axi_arsize_i(32),
        .axi_arburst_i(0),
        .axi_rlast_o(0),
        .axi_bvalid_o(0),
        .axi_arready_o(0),
        .axi_rvalid_o(0),
        .axi_rdata_o(dsp_result)
    );

    // Memory Block
    memory_block (
        .clk(clock_control),
        .reset_in(reset_in),
        .address_a (operand_a_cdc),
        .address_b (operand_b_cdc),
        .address_c (operand_c_cdc),
        .data_a (data_a_cdc),
        .data_b (data_b_cdc),
        .data_c (data_c_cdc),
        .op_select (op_select_cdc),
        .start (start_cdc),
        .result_address (result)
    );

    // DSP Block
    dsp_block (
        .clk(clock_control),
        .reset_in(reset_in),
        .operand_a (operand_a_cdc),
        .operand_b (operand_b_cdc),
        .operand_c (operand_c_cdc),
        .op_select (op_select_cdc),
        .start (start_cdc),
        .result (dsp_result)
    );

    // CDC Synchronizers
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_a (.clk(clock_control), .clk_src(axi_clk_in), .data_in(operand_a_cdc), .data_out(operand_a));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_b (.clk(clock_control), .clk_src(axi_clk_in), .data_in(operand_b_cdc), .data_out(operand_b));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_c (.clk(clock_control), .clk_src(axi_clk_in), .data_in(operand_c_cdc), .data_out(operand_c));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_start (.clk(clock_control), .clk_src(axi_clk_in), .data_in(start_cdc), .data_out(start));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_rvalid_o (.clk(clock_control), .clk_src(axi_clk_in), .data_in(axi_rvalid_o), .data_out(0));

output.rtl/axi_register.sv:
module axi_register(
    input clock,
    input rst_n,
    input [ADDR_WIDTH-1:0] awaddr,
    input [DATA_WIDTH-1:0] wdata,
    input [DATA_WIDTH/8-1:0] wstrb,
    input wvalid,
    input bready,
    input [ADDR_WIDTH-1:0] araddr,
    input arvalid,
    input rvalid,
    input done,
    output [1:0] bresp,
    output [1:0] rresp,
    output start,
    output writeback,
    output [20-1:0] beat,
    output [1:0] rvalid_o,
    output [1:0] bvalid_o,
    output [1:0] rvalid_o,
    output [1:0] bvalid_o
);

    // Address decoding logic
    reg [ADDR_WIDTH-1:0] address;
    always @posedge clock or @(!rst_n &posedge clock) begin
        if (rst_n) 
            beat = 0;
            start = 0;
            done = 0;
            ID = 0x00010001;
            beat_o = 0;
            start_o = 0;
            writeback_o = 0;
            $valid = 0;
        else
            address = awaddr;
            if (arvalid) begin
                address = araddr;
                rvalid_o = 1;
            end
            if (wvalid) begin
                beat_o = beat;
                start_o = (wdata & 1);
                writeback_o = (wdata & 1);
                $valid = 1;
            end
        end
    end

    // Beat counter update
    reg [20-1:0] beat_reg;
    always @posedge clock or @(!rst_n &posedge clock) begin
        if ($valid) beat_reg = beat_reg + 1;
    end

    // ID register
    reg [32-1:0] ID;
    always @posedge clock or @(!rst_n &posedge clock) begin
        if ($valid) ID = 0x00010001;
    end

    // Response handling
    case (bresp)
        2'b00: bvalid_o = 0;
        2'b10: bvalid_o = 1;
        default: bvalid_o = 0;
    endcase

    case (rresp)
        2'b00: rvalid_o = 1;
        2'b10: rvalid_o = 0;
        default: rvalid_o = 1;
    endcase
endmodule

output.rtl/axis_resize.sv:
module axis_resize (
  input clock,
  input resetn,
  input s_valid,
  input s_data,
  output s_ready,
  output m_valid,
  input m_ready,
  output m_data
);

  reg s_valid_reg = 1;
  reg m_valid_reg = 0;
  reg m_data_reg;

  if (resetn) 
    m_data = 8'b0;
    s_ready = 1;
  else 
    if (m_ready) 
      m_data = (s_data >> 8);
      m_valid = 1;
      s_ready = 1;
    else 
      m_valid = 0;
      s_ready = 0;
    end
  end

  // Negative edge-sensitive assignment
  m_data = m_data_reg;
  m_valid = m_valid_reg;

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale(
    input clock,
    input resetn,
    input dfmt_enable,
    input dfmt_type,
    input dfmt_se,
    input s_axis_valid,
    input s_axis_data,
    output m_axis_valid,
    output m_axis_data,
    output s_axis_ready
);

    // Reset handling
    always @* begin
        if (resetn) begin
            s_axis_ready = 1;
            m_axis_valid = 0;
            m_axis_data = 8'b00000000;
        end else begin
            // Data processing
            if (dfmt_enable) begin
                // Perform data formatting
                if (dfmt_type) begin
                    // Inverted MSB carry forward
                    s_axis_data[23] = ~s_axis_data[23];
                end else begin
                    // Normal MSB carry forward
                    s_axis_data[23] = s_axis_data[23];
                end

                if (dfmt_se) begin
                    // Sign extension
                    s_axis_data[22:0] = s_axis_data[23] & s_axis_data[22:0];
                end else begin
                    // Zero extension
                    s_axis_data[22:0] = 8'b00000000;
                end

                // Upscale to 32 bits
                m_axis_data = (s_axis_data << 8) | s_axis_data[23:23];
                m_axis_data[31] = 0;
            else begin
                // No data formatting, just pad with zeros
                m_axis_data = (s_axis_data << 8) | 8'b00000000;
                m_axis_data[31] = 0;
            end
        end
    end

    // Set ready state based on s_axis_valid
    s_axis_ready = s_axis_valid;
endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32
)(
    input           clk_i,
    input           rst_i,
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    input           inport_awready_o,
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    input           inport_wready_o,
    input           inport_bready_i,
    input           inport_bvalid_i,
    output          inport_bresp_o,
    output          inport_rvalid_o,
    output  [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,
    output          inport_awready_r,
    output          inport_wready_r,
    output  [ADDR_WIDTH-1:0]   outport_awaddr_o,
    output          outport_awvalid_o,
    output  [DATA_WIDTH-1:0]   outport awdata_o,
    output [3:0]    outport awstrb_o,
    output          outport_wready_o,
    output          outport_bvalid_i,
    output  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    output  [ADDR_WIDTH-1:0]   outport_araddr_o,
    output          outport_arvalid_o,
    output  [DATA_WIDTH-1:0]   outport ardata_o,
    output [1:0]    outport_arresp_o,
    output          outport_rready_o,
    output  [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    output          outport_peripheral0_awvalid_o,
    output  [DATA_WIDTH-1:0]   outport_peripheral0 awdata_o,
    output [3:0]    outport_peripheral0 awstrb_o,
    output          outport_peripheral0_wready_o,
    output          outport_peripheral0_wvalid_o,
    output  [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    output          outport_peripheral0_bvalid_o,
    output  [1:0]    outport_peripheral0_bresp_o,
    output          outport_peripheral0_bready_o,
    output  [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    output          outport_peripheral0_arvalid_o,
    output  [DATA_WIDTH-1:0]   outport_peripheral0 ardata_o,
    output [1:0]    outport_peripheral0 arresp_o,
    output          outport_peripheral0_rready_o
);

`define ADDR_ELSE 0
`define PERIPH0_ADDR 32'h80000000
`define PERIPH0_MASK 32'h80000000

// AXI: Read
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_ELSE-1:0]  read_port_q;
reg [`ADDR_ELSE-1:0]  read_port_r;

always @ *
if (rst_i)
    read_pending_q <= 4'b0;
    read_port_q    <= `ADDR_ELSE'b0;
else
    read_pending_q <= read_pending_r;
    if (inport_arvalid_i && inport_arready_o)
        read_port_q <= read_port_r;

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_ELSE'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_rready_o  = inport_rready_i;

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_ELSE'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_rready_o  = inport_rready_i;

// AXI: Write
reg [3:0]              write_pending_q;
reg [3:0]              write_pending_r;
reg [`ADDR_ELSE-1:0]  write_port_q;
reg [`ADDR_ELSE-1:0]  write_port_r;

always @ (posedge clk_i)
if (rst_i)
    write_pending_q <= 4'b0;
    write_port_q    <= `ADDR_ELSE'b0;
else
    write_pending_q <= write_pending_r;
    if (inport_awvalid_i && inport_awready_o && (!wr_data_accepted_w))
        write_pending_q <= 1'b1;
    else if (wr_data_accepted_w)
        write_pending_q <= 4'b0;

always @ (posedge clk_i)
if (rst_i)
    wvalid_q <= 1'b0;
else if (inport_wvalid_i && inport_wready_o && !wr_cmd_accepted_w)
    wvalid_q <= 1'b1;
else if (wr_cmd_accepted_w)
    wvalid_q <= 4'b0;

wire wr_cmd_accepted_w  = (inport_awvalid_i && inport_awready_o) || wvalid_q;
wire wr_data_accepted_w = (inport_wvalid_i  && inport_wready_o)  || wvalid_q;

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_ELSE'd0);
assign outport_awaddr_o  = inport_awaddr_i;
assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_ELSE'd0);
assign outport_wdata_o   = inport_wdata_i;
assign outport_wstrb_o   = inport_wstrb_i;
assign outport_bready_o  = inport_bready_i;

assign outport_peripheral0_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_ELSE'd1);
assign outport_peripheral0_awaddr_o  = inport_awaddr_i;
assign outport_peripheral0_wvalid_o  = inport_wvalid_i & ~wvalid_q & ((inport_awvalid_i && write_accept_w) || awvalid_q) & (write_port_r == `ADDR_ELSE'd1);
assign outport_peripheral0_wdata_o   = inport_wdata_i;
assign outport_peripheral0_wstrb_o   = inport_wstrb_i;
assign outport_peripheral0_bready_o  = inport_bready_i;

reg outport_bvalid_r;
reg [1:0]  outport_bresp_r;

always @ *
begin
    case (write_port_q)
        `ADDR_ELSE'd1:
        begin
            outport_bvalid_r = outport_peripheral0_bvalid_i;
            outport_bresp_r  = outport_peripheral0_bresp_i;
        end
        default:
        begin
            outport_bvalid_r = outport_bvalid_i;
            outport_bresp_r  = outport_bresp_i;
        end
    endcase
end

assign inport_bvalid_o  = outport_bvalid_r;
assign inport_bresp_o   = outport_bresp_r;

reg inport_awready_r;
reg inport_wready_r;

always @ *
begin
    case (write_port_r)
        `ADDR_ELSE'd1:
        begin
            inport_awready_r = outport_peripheral0_awready_i;
            inport_wready_r  = outport_peripheral0_wready_i;
        end
        default:
        begin
            inport_awready_r = outport_awready_i;
            inport_wready_r  = outport_wready_i;
        end
    endcase
end

assign inport_awready_o = write_accept_w & ~awvalid_q & inport_awready_r;
assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;

endmodule

input.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_peripheral0_rresp_i,
    input           outport_peripheral0_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output          outport_peripheral0_rready_o
);

`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

//-----------------------------------------------------------------
// AXI: Read
//-----------------------------------------------------------------
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_SEL_W-1:0]  read_port_q;
reg [`ADDR_SEL_W-1:0]  read_port_r;

always @ *
begin
    read_port_r = `ADDR_SEL_W'b0;
    if ((inport_araddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) read_port_r = `ADDR_SEL_W'd1;
end

wire read_incr_w = (inport_arvalid_i && inport_arready_o);
wire read_decr_w = (inport_rvalid_o && inport_rready_i);

always @ *
begin
    read_pending_r = read_pending_q;

    if (read_incr_w && !read_decr_w)
        read_pending_r = read_pending_r + 4'd1;
    else if (!read_incr_w && read_decr_w)
        read_pending_r = read_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    read_pending_q <= 4'b0;
    read_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    read_pending_q <= read_pending_r;

    // Read command accepted
    if (inport_arvalid_i && inport_arready_o)
    begin
        read_port_q <= read_port_r;
    end
end

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_rready_o  = inport_rready_i;

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_rready_o  = inport_rready_i;

reg        outport_rvalid_r;
reg [DATA_WIDTH-1:0] outport_rdata_r;
reg [1:0]  outport_rresp_r;

always @ *
begin
    case (read_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_rvalid_r = outport_peripheral0_rvalid_i;
        outport_rdata_r  = outport_peripheral0_rdata_i;
        outport_rresp_r  = outport_peripheral0_rresp_i;
    end
    default:
    begin
        outport_rvalid_r = outport_rvalid_i;
        outport_rdata_r  = outport_rdata_i;
        outport_rresp_r  = outport_rresp_i;
    end
    endcase
end

assign inport_rvalid_o  = outport_rvalid_r;
assign inport_rdata_o   = outport_rdata_r;
assign inport_rresp_o   = outport_rresp_r;

reg inport_arready_r;
always @ *
begin
    case (read_port_r)
    `ADDR_SEL_W'd1:
        inport_arready_r = outport_peripheral0_arready_i;
    default:
        inport_arready_r = outport_arready_i;
    endcase
end

assign inport_arready_o = read_accept_w & inport_arready_r;

//-------------------------------------------------------------
// Write Request
//-------------------------------------------------------------
reg awvalid_q;
reg wvalid_q;

wire wr_cmd_accepted_w  = (inport_awvalid_i && inport_awready_o) || awvalid_q;
wire wr_data_accepted_w = (inport_wvalid_i  && inport_wready_o)  || wvalid_q;

always @ (posedge clk_i )
if (rst_i)
    awvalid_q <= 1'b0;
else if (inport_awvalid_i && inport_awready_o && (!wr_data_accepted_w))
    awvalid_q <= 1'b1;
else if (wr_data_accepted_w)
    awvalid_q <= 1'b0;

always @ (posedge clk_i )
if (rst_i)
    wvalid_q <= 1'b0;
else if (inport_wvalid_i && inport_wready_o && !wr_cmd_accepted_w)
    wvalid_q <= 1'b1;
else if (wr_cmd_accepted_w)
    wvalid_q <= 1'b0;

//-----------------------------------------------------------------
// AXI: Write
//-----------------------------------------------------------------
reg [3:0]              write_pending_q;
reg [3:0]              write_pending_r;
reg [`ADDR_SEL_W-1:0]  write_port_q;
reg [`ADDR_SEL_W-1:0]  write_port_r;

always @ *
begin    
    if (inport_awvalid_i & ~awvalid_q)
    begin
        write_port_r = `ADDR_SEL_W'b0;
        if ((inport_awaddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) write_port_r = `ADDR_SEL_W'd1;
    end
    else
        write_port_r = write_port_q;
end

wire write_incr_w = (inport_awvalid_i && inport_awready_o);
wire write_decr_w = (inport_bvalid_o  && inport_bready_i);

always @ *
begin
    write_pending_r = write_pending_q;

    if (write_incr_w && !write_decr_w)
        write_pending_r = write_pending_r + 4'd1;
    else if (!write_incr_w && write_decr_w)
        write_pending_r = write_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    write_pending_q <= 4'b0;
    write_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    write_pending_q <= write_pending_r;

    // Write command accepted
    if (inport_awvalid_i && inport_awready_o)
    begin
        write_port_q <= write_port_r;
    end
end

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
assign outport_awaddr_o  = inport_awaddr_i;
assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
assign outport_wdata_o   = inport_wdata_i;
assign outport_wstrb_o   = inport_wstrb_i;
assign outport_bready_o  = inport_bready_i;

assign outport_peripheral0_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_awaddr_o  = inport_awaddr_i;
assign outport_peripheral0_wvalid_o  = inport_wvalid_i & ~wvalid_q & ((inport_awvalid_i && write_accept_w) || awvalid_q) & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_wdata_o   = inport_wdata_i;
assign outport_peripheral0_wstrb_o   = inport_wstrb_i;
assign outport_peripheral0_bready_o  = inport_bready_i;

reg        outport_bvalid_r;
reg [1:0]  outport_bresp_r;

always @ *
begin
    case (write_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_bvalid_r = outport_peripheral0_bvalid_i;
        outport_bresp_r  = outport_peripheral0_bresp_i;
    end
    default:
    begin
        outport_bvalid_r = outport_bvalid_i;
        outport_bresp_r  = outport_bresp_i;
    end
    endcase
end

assign inport_bvalid_o  = outport_bvalid_r;
assign inport_bresp_o   = outport_bresp_r;

reg inport_awready_r;
reg inport_wready_r;

always @ *
begin
    case (write_port_r)
    `ADDR_SEL_W'd1:
    begin
        inport_awready_r = outport_peripheral0_awready_i;
        inport_wready_r  = outport_peripheral0_wready_i;
    end
    default:
    begin
        inport_awready_r = outport_awready_i;
        inport_wready_r  = outport_wready_i;
    end        
    endcase
end

assign inport_awready_o = write_accept_w & ~awvalid_q & inport_awready_r;
assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;


endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter TIMEOUT_THRESHOLD = 8  // configurable timeout in cycles
)(
    input           clk_i,
    input           rst_i,
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Address Channel (AW)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bvalid_i,
    input  [1:0]    inport_bresp_i,
    output          inport_bready_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_rvalid_o,
    // Master Read Data Channel (R)
    input           inport_rvalid_i,
    input  [DATA_WIDTH-1:0]   inport_rdata_i,
    input  [1:0]    inport_rresp_i,
    output          inport_rready_o,
    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input           outport_peripheral0_bready_i,
    output          outport_peripheral0_bvalid_o,
    output [1:0]    outport_peripheral0_bresp_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input           outport_peripheral0_rready_i,
    output          outport_peripheral0_rvalid_i,
    output [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output [1:0]    outport_peripheral0_rresp_i,
    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awvalid_o,
    output          outport_peripheral0_awready_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wvalid_o,
    output          outport_peripheral0_wready_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input           outport_peripheral0_bvalid_o,
    output          outport_peripheral0_bready_o,
    output [1:0]    outport_peripheral0_bresp_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arvalid_o,
    output          outport_peripheral0_arready_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input           outport_peripheral0_rvalid_o,
    output          outport_peripheral0_rready_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_rdata_o,
    output [1:0]    outport_peripheral0_rresp_o,
    // Timeout Flag
    output          timeout_flag
    // Timeout Timer
    reg [3:0] timeout_read_tmr = 0;
    reg [3:0] timeout_write_tmr = 0;
    // Timeout Detection Logic
    always @posedge clk_i begin
        case (rst_i)
            timeout_read_tmr <= 0;
            timeout_write_tmr <= 0;
        endcase
    end
    // Read Timeout Detection
    always @posedge clk_i begin
        if (inport_arvalid_i && inport_arready_o) begin
            timeout_read_tmr <= timeout_read_tmr + 1;
            if (timeout_read_tmr >= TIMEOUT_THRESHOLD) begin
                timeout_flag = 1;
            end
        end
    end
    // Write Timeout Detection
    always @posedge clk_i begin
        if (inport_awvalid_i && inport_awready_o) begin
            timeout_write_tmr <= timeout_write_tmr + 1;
            if (timeout_write_tmr >= TIMEOUT_THRESHOLD) begin
                timeout_flag = 1;
            end
        end
    end
    // Reset Timeout Timer
    always @posedge clk_i begin
        case (rst_i)
            timeout_read_tmr <= 0;
            timeout_write_tmr <= 0;
        endcase
    end
    // Connect timeout_flag to peripheral outputs
    assign outport_peripheral0_rready_o = timeout_flag;
    assign outport_peripheral0_bready_o = timeout_flag;

output.rtl/precision_counter_axi.sv:
module precision_counter_axi(
    parameter C_S_AXI_DATA_WIDTH,
    parameter C_S_AXI_ADDR_WIDTH
);

  // AXI4-Lite protocol-related signals
  input axi_aclk;
  input axi_aresetn;
  input axi_awaddr;
  input axi_araddr;
  input axi_awvalid;
  input axi_arvalid;
  input axi_wdata;
  input axi_wstrb;
  input axi_wvalid;
  input axi_rdata;
  output axi_rvalid;

  output axi_bvalid;
  output axi_bready;
  output axi_rready;
  output axi_ap_done;
  output irq;

  // Control and status registers
  register [C_S_AXI_DATA_WIDTH-1:0] axi_wdata_reg;
  register [C_S_AXI_DATA_WIDTH-1:0] axi_rdata_reg;
  register [C_S_AXI_ADDR_WIDTH-1:0] axi_waddr_reg;
  register [C_S_AXI_ADDR_WIDTH-1:0] axi_raddr_reg;
  register [31:0] slv_reg_ctl;
  register [31:0] slv_reg_t;
  register [31:0] slv_reg_v;
  register [31:0] slv_reg_irq_mask;
  register [31:0] slv_reg_irq_thresh;

  // Module state
  reg done;

  // Parameters
  parameter AXI4LITE_WIDTH = 32;

  // Module initialization
  initial begin
    done = 0;
    // Initialize all registers to 0
    axi_wdata_reg = 0;
    axi_rdata_reg = 0;
    axi_waddr_reg = 0;
    axi_raddr_reg = 0;
    slv_reg_v = 0;
    slv_reg_t = 0;
    slv_reg_irq_mask = 0;
    slv_reg_irq_thresh = 0;
  end

  // Start/Stop control
  always @*+begin
    if (axi_awvalid && axi_arvalid) begin
      if (slv_reg_v == 0 && done == 0) begin
        // Start countdown
        slv_reg_v = 0;
        done = 1;
      end
    end
  end
  always @*+end

  // Write operation
  always @*+begin
    if (axi_wvalid && axi_awvalid) begin
      if (done == 0) begin
        axi_awready = 1;
        axi_wdata_reg = axi_wdata;
        axi_wstrb = axi_wstrb;
        axi_wvalid = 1;
      end else begin
        // Wait for write ready
        while (!axi_wready) continue;
      end
    end
  end
  always @*+end

  // Read operation
  always @*+begin
    if (axi_rvalid && axi_arvalid) begin
      if (done == 0) begin
        axi_arready = 1;
        axi_rdata_reg = axi_rdata;
        axi_rvalid = 1;
      end else begin
        // Wait for read ready
        while (!axi_rready) continue;
      end
    end
  end
  always @*+end

  // AXI4-Lite handshake completion
  always @*+begin
    if (axi_awvalid && axi_arvalid) begin
      if (done == 0) begin
        axi_bvalid = 1;
        axi_bready = 1;
      end else begin
        // Wait for handshake completion
        while (!axi_bready && !axi_rready) continue;
      end
    end
  end
  always @*+end

  // Interrupt handling
  always @*+begin
    if (irq) begin
      if (slv_reg_irq_mask & 1) begin
        if (slv_reg_v == slv_reg_irq_thresh) begin
          irq = 1;
        end
      end
      // Mask the irq signal
      irq = ~ (irq & slv_reg_irq_mask);
    end
  end
  always @*+end
endmodule

