output.rtl/axis_joiner.sv:
module axis_joiner(
    input clock,
    input rst,
    input [7:0] s_axis_tdata_1,
    input s_axis_tvalid_1,
    output s_axis_tready_1,
    input s_axis_tlast_1,
    input [7:0] s_axis_tdata_2,
    input s_axis_tvalid_2,
    output s_axis_tready_2,
    input s_axis_tlast_2,
    input [7:0] s_axis_tdata_3,
    input s_axis_tvalid_3,
    output s_axis_tready_3,
    output [7:0] m_axis_tdata,
    output s_axis_tvalid,
    output s_axis_tready,
    output s_axis_tlast,
    output [1:0] s_axis_tuser,
    output busy
);

    // FSM states
    enum FSMState {
        IDLE,
        STATE_1,
        STATE_2,
        STATE_3
    };

    // FSM state
    FSMState fsm_state = IDLE;
    // Current input data
    reg [7:0] data;
    // Tags for source streams
    s_axis_tuser = 0b00;

    // FSM transition logic
    always clock begin
        case(fsm_state)
            IDLE:
                if (s_axis_tvalid_1) begin
                    fsm_state = STATE_1;
                    data = s_axis_tdata_1;
                    s_axis_tuser = 0b01;
                end
                else if (s_axis_tvalid_2) begin
                    fsm_state = STATE_2;
                    data = s_axis_tdata_2;
                    s_axis_tuser = 0b10;
                end
                else if (s_axis_tvalid_3) begin
                    fsm_state = STATE_3;
                    data = s_axis_tdata_3;
                    s_axis_tuser = 0b11;
                end
                else begin
                    fsm_state = IDLE;
                end
            STATE_1:
                if (s_axis_tlast_1) begin
                    fsm_state = IDLE;
                    busy = 1;
                end else begin
                    busy = 0;
                end
                data = s_axis_tdata_1;
                s_axis_tuser = 0b01;
            STATE_2:
                if (s_axis_tlast_2) begin
                    fsm_state = IDLE;
                    busy = 1;
                end else begin
                    busy = 0;
                end
                data = s_axis_tdata_2;
                s_axis_tuser = 0b10;
            STATE_3:
                if (s_axis_tlast_3) begin
                    fsm_state = IDLE;
                    busy = 1;
                end else begin
                    busy = 0;
                end
                data = s_axis_tdata_3;
                s_axis_tuser = 0b11;
        end

        // Mux to select output data
        case(fsm_state)
            IDLE:
                m_axis_tdata = 0;
                s_axis_tvalid = 0;
                s_axis_tready = 0;
                s_axis_tlast = 0;
                s_axis_tuser = 0;
                busy = 0;
                break;
            STATE_1:
                m_axis_tdata = data;
                s_axis_tvalid = 1;
                s_axis_tready = 1;
                s_axis_tlast = s_axis_tlast_1;
                s_axis_tuser = 0b01;
                busy = 1;
                break;
            STATE_2:
                m_axis_tdata = data;
                s_axis_tvalid = 1;
                s_axis_tready = 1;
                s_axis_tlast = s_axis_tlast_2;
                s_axis_tuser = 0b10;
                busy = 1;
                break;
            STATE_3:
                m_axis_tdata = data;
                s_axis_tvalid = 1;
                s_axis_tready = 1;
                s_axis_tlast = s_axis_tlast_3;
                s_axis_tuser = 0b11;
                busy = 1;
                break;
        end

        // Reset initialization
        initial begin
            fsm_state = IDLE;
            busy = 0;
            m_axis_tdata = 0;
            s_axis_tvalid = 0;
            s_axis_tready = 0;
            s_axis_tlast = 0;
            s_axis_tuser = 0;
        end
    end
endmodule

output.rtl/axis_mux.sv:
module axis_mux #(
  parameter integer C_AXIS_DATA_WIDTH = 32,
  parameter integer C_AXIS_TUSER_WIDTH = 4,
  parameter integer C_AXIS_TID_WIDTH   = 2,
  parameter integer C_AXIS_TDEST_WIDTH = 2,
  parameter integer NUM_INPUTS         = 4
)(
  input  wire                                   aclk,
  input  wire                                   aresetn,
  input  wire [$clog2(NUM_INPUTS)-1:0]          sel,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tvalid,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tready,
  input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH-1:0]   s_axis_tdata,
  input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH/8-1:0] s_axis_tkeep,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tlast,
  input  wire [NUM_INPUTS*C_AXIS_TID_WIDTH-1:0] s_axis_tid,
  input  wire [NUM_INPUTS*C_AXIS_TDEST_WIDTH-1:0] s_axis_tdest,
  input  wire [NUM_INPUTS*C_AXIS_TUSER_WIDTH-1:0] s_axis_tuser,
  output wire                                   m_axis_tvalid,
  output wire [C_AXIS_DATA_WIDTH-1:0]           m_axis_tdata,
  output wire [C_AXIS_DATA_WIDTH/8-1:0]         m_axis_tkeep,
  output wire                                   m_axis_tlast,
  output wire [C_AXIS_TID_WIDTH-1:0]            m_axis_tid,
  output wire [C_AXIS_TDEST_WIDTH-1:0]          m_axis_tdest,
  output wire [C_AXIS_TUSER_WIDTH-1:0]          m_axis_tuser
);

// Determine which input is active
integer active_input = (sel >> ($clog2(NUM_INPUTS)-1)) & (NUM_INPUTS-1);
wire [0:NUM_INPUTS-1] sel_reg;

always @* begin
  // If sel is out of bounds, all outputs are inactive
  if (sel >= NUM_INPUTS || sel < 0) begin
    m_axis_tvalid = 0;
    m_axis_tready = 0;
    m_axis_tdata = 0;
    m_axis_tkeep = 0;
    m_axis_tlast = 0;
    m_axis_tid = 0;
    m_axis_tdest = 0;
    m_axis_tuser = 0;
    return;
  end

  // Extract signals from the active input
  wire [C_AXIS_DATA_WIDTH-1:0] tdata;
  wire [C_AXIS_DATA_WIDTH/8-1:0] tkeep;
  wire tid;
  wire tdest;
  wire tuser;

  always @*+1 begin
    tdata = s_axis_tdata[active_input * C_AXIS_DATA_WIDTH: (active_input * C_AXIS_DATA_WIDTH) + C_AXIS_DATA_WIDTH-1];
    tkeep = s_axis_tkeep[active_input * C_AXIS_DATA_WIDTH/8: (active_input * C_AXIS_DATA_WIDTH/8) + C_AXIS_DATA_WIDTH/8-1];
    tid = s_axis_tid[active_input * C_AXIS_TID_WIDTH: (active_input * C_AXIS_TID_WIDTH) + C_AXIS_TID_WIDTH-1];
    tdest = s_axis_tdest[active_input * C_AXIS_TDEST_WIDTH: (active_input * C_AXIS_TDEST_WIDTH) + C_AXIS_TDEST_WIDTH-1];
    tuser = s_axis_tuser[active_input * C_AXIS_TUSER_WIDTH: (active_input * C_AXIS_TUSER_WIDTH) + C_AXIS_TUSER_WIDTH-1];
  end

  // Output signals
  m_axis_tvalid = any(s_axis_tvalid);
  m_axis_tready = s_axis_tready[active_input];
  wire local_tready;
  wire [NUM_INPUTS-1:0] temp_tready;

  // Propagate backpressure
  always @*+1 begin
    local_tready = s_axis_tready[active_input];
    temp_tready[active_input] = local_tready;
    // Bubble backpressure
    for (integer i = active_input - 1; i >= 0; i--) begin
      temp_tready[i] = temp_tready[i+1];
    end
    m_axis_tready = temp_tready[0];
  end

  // Output data
  m_axis_tdata = tdata;
  m_axis_tkeep = tkeep;
  m_axis_tlast = tlast[active_input];
  m_axis_tid = tid;
  m_axis_tdest = tdest;
  m_axis_tuser = tuser;

endmodule

output.rtl/barrel_shifter_8bit.sv:
module barrel_shifter_8bit (
    input data_in,
    input shift_bits,
    input left_right,
    output data_out
);

parameter shift_reg = [
    // shift 0
    (data_in, data_in),
    // shift 1
    (data_in << 1, data_in >> 1),
    // shift 2
    (data_in << 2, data_in >> 2),
    // shift 3
