module bus_arbiter (
    input wire reset,
    input wire clk,
    input wire req1,
    input wire req2,
    output reg grant1,
    output reg grant2
);
    // State encoding using localparam
    localparam IDLE    = 3'b000,
               GRANT_1 = 3'b001,
               GRANT_2 = 3'b010,
               CLEAR   = 3'b011;

    // State registers
    reg [2:0] state;
    reg [2:0] next_state;

    // Sequential logic for state transition
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // Combinational logic for next state
    always @(*) begin
        // Default assignments
        next_state = state;

        case (state)
            IDLE: 
                if (req1 && !req2) next_state = GRANT_1;
                else if (req2 && !req1) next_state = GRANT_2;
                else if (req1 && req2) next_state = GRANT_2;
                else next_state = CLEAR;
                break;
            GRANT_1: 
                if (req2) next_state = GRANT_2;
                else next_state = IDLE;
                break;
            GRANT_2: 
                if (req1) next_state = GRANT_1;
                else next_state = IDLE;
                break;
            CLEAR: 
                if (req1 || req2) next_state = GRANT_1;
                else next_state = CLEAR;
                break;
        endcase
    end

    // Output logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            grant1 <= 1'b0;
            grant2 <= 1'b0;
        end else begin
            // Grant assignments based on next_state
            case (next_state)
                GRANT_1: grant1 = 1; grant2 = 0;
                GRANT_2: grant1 = 0; grant2 = 1;
                IDLE:   grant1 = 0; grant2 = 0;
                CLEAR:  grant1 = 0; grant2 = 0;
            endcase
        end
    end

endmodule

