module lru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire lru_slot_found;
    wire [$clog2(NWAYS)-1:0] lru_slot;

    integer i, n, w;

    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        else begin

            // Hit Case
            if (access) begin
                // Store current value of accessed way
                integer prev_value = recency[index][way_select];

                // Update accessed way to max value
                recency[index][way_select] <= $clog2(NWAYS)'(NWAYS-1);

                // Decrement counters for ways with higher values
                for (w = 0; w < NWAYS; w = w + 1) begin
                    if (w != way_select) begin
                        if (recency[index][w] > prev_value) begin
                            recency[index][w] <= recency[index][w] - 1;
                        end
                    end
                end
            end

            // Miss Case
            if (!access) begin
                // Find the way with minimum counter value
                integer min_val = $clog2(NWAYS)'(NWAYS-1);
                integer lru_ways = 0;

                for (i = 0; i < NINDEXES; i = i + 1) begin
                    for (w = 0; w < NWAYS; w = w + 1) begin
                        if (recency[i][w] < min_val) begin
                            min_val = recency[i][w];
                            lru_ways = w;
                        end
                    end
                end

                // Update replaced way to max value
                recency[index][lru_ways] <= $clog2(NWAYS)'(NWAYS-1);

                // Decrement counters for ways with higher values
                for (w = 0; w < NWAYS; w = w + 1) begin
                    if (w != lru_ways) begin
                        if (recency[index][w] > min_val) begin
                            recency[index][w] <= recency[index][w] - 1;
                        end
                    end
                end
            end
        end
    end
endmodule

output.rtl/mru_counter_policy.sv:
module mru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire [$clog2(NWAYS)-1:0] mru_slot;

    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        else begin
            if (access) begin
                // Hit case: Update recency array
                way = way_select;
                offset = way * $clog2(NWAYS);
                recency[index][way] <= (NWAYS - 1);
                for (n = way - 1; n >= 0; n = n - 1) begin
                    if (recency[index][n + offset] == (NWAYS - 1)) break;
                    recency[index][n + offset] <= recency[index][n + offset] - 1;
                end
            else begin
                // Miss case: Find MRU slot for replacement
                max_counter = 0;
                max_way = 0;
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (recency[index][n + offset] > recency[index][max_way + offset]) begin
                        max_way = n;
                        max_counter = recency[index][max_way + offset];
                    end
                end
                way_replace = max_way;
                offset = max_way * $clog2(NWAYS);
                recency[index][offset] <= (NWAYS - 1);
                for (n = max_way - 1; n >= 0; n = n - 1) begin
                    if (recency[index][n + offset] == (NWAYS - 1)) break;
                    recency[index][n + offset] <= recency[index][n + offset] - 1;
                end
            end
        end
    end

endmodule

output.rtl/lfu_counter_policy.sv:
module lfu_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32,
    parameter COUNTERW = 2
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned MAX_FREQUENCY = $pow(2, COUNTERW) - 1;

    // Frequency array to track next way to be replaced
    reg [(NWAYS * COUNTERW)-1:0] frequency [NINDEXES-1:0];

    integer i, n;

    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    frequency[i][(n * COUNTERW) +: COUNTERW] <= COUNTERW'(0);
                end
            end
        else begin
            if (access) begin
                // Hit handling
                integer idx = index * COUNTERW + way_select;
                frequency[idx] <= frequency[idx] + 1;
                if (frequency[idx] > MAX_FREQUENCY) {
                    frequency[idx] <= MAX_FREQUENCY;
                }
                if (frequency[idx] == MAX_FREQUENCY) {
                    // Decrement counters of other ways with counter > 2
                    for (n = 0; n < NWAYS; n = n + 1) {
                        if (n != way_select) {
                            integer freq_idx = index * COUNTERW + n;
                            if (frequency[freq_idx] > 2) {
                                frequency[freq_idx] <= frequency[freq_idx] - 1;
                            }
                        }
                    }
                }
            else begin
                // Miss handling
                integer min_counter = MAX_FREQUENCY;
                integer min_way = 0;
                integer current_min_idx = 0;
                for (n = 0; n < NWAYS; n = n + 1) {
                    integer freq_idx = index * COUNTERW + n;
                    if (frequency[freq_idx] < min_counter) {
                        min_counter = frequency[freq_idx];
                        min_way = n;
                        current_min_idx = n;
                    } else if (frequency[freq_idx] == min_counter) {
                        if (n < min_way) {
                            min_way = n;
                            current_min_idx = n;
                        }
                    }
                }
                way_replace = current_min_idx;
            end
        end
    end
endmodule

output.rtl/pseudo_lru_tree_policy.sv:
module pseudo_lru_tree_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned NBITS_TREE = NWAYS - 1;

    // Recency array to track next way to be replaced
    reg [NBITS_TREE-1:0] recency [NINDEXES-1:0];

    wire [NBITS_TREE-1:0] recency_updated;
    wire [$clog2(NWAYS)-1:0] pseudo_lru_slot;

    integer i;

    // Sequential logic for reset and recency updates
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i++) begin
                recency[i] <= NBITS_TREE'(0);
            end
        end else begin
            if (access) begin
                recency[index] <= recency_updated;
            end
        end
    end

    // Update recency array logic
    function void update_recurse(int index, int way, int depth) {
        if (depth >= $clog2(NWAYS)) return;
        if (way <= 1) begin
            recency[index] [depth] = 1;
            update_recurse(index, way + 2, depth + 1);
        end else begin
            recency[index] [depth] = 1;
            update_recurse(index, way - 2, depth + 1);
        end
    }

    // Implement the code for recency_updated wire
    always_ff @ (posedge clock) begin
        if (reset) recency_updated <= 0;
        else if (access) begin
            update_recurse(index, way_select, 0);
            recency_updated <= recency[index];
        end else begin
            // Find LRU slot
            pseudo_lru_slot <= slot_select_pseudo_lru_tree#(NWAYS)(recency[index]);
            // Update replaced way to MRU
            update_recurse(index, pseudo_lru_slot, 0);
            recency_updated <= recency[index];
        end
    end

    // Select the Pseudo LRU slot
    slot_select_pseudo_lru_tree#(
        .NWAYS (NWAYS)
    ) slot_select_unit (
        .array (recency[index]),
        .index (pseudo_lru_slot)
    );

    assign way_replace = pseudo_lru_slot;

endmodule : pseudo_lru_tree_policy

module slot_select_pseudo_lru_tree #(
    parameter NWAYS = 4
)(
    input [NWAYS-2:0] array,
    output logic [$clog2(NWAYS)-1:0] index
);

    localparam int unsigned MAX_DEPTH = $clog2(NWAYS);

    integer depth;
    logic [$clog2(NWAYS)-1:0] step;
    logic direction;

    always_comb begin
        depth = 0;
        step = 0;
        direction = 0;
        while (depth < MAX_DEPTH) begin
            if (array[step] == 0) begin
                step = (step == 0) ? 1 : 0;
                direction = 0;
            else
                step = (step == 1) ? 0 : 1;
                direction = 1;
            end
            depth +.1;
        end
        index = step;
    end

endmodule

