module fifo_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    // FIFO array to track next way to be replaced
    reg [$clog2(NWAYS)-1:0] fifo_array [NINDEXES-1:0];

    integer i;

    // Sequential logic for reset and fifo_array updates
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i++) begin
                fifo_array[i] <= $clog2(NWAYS)'(0);
            end
        else begin
            if (access) begin
                // Set the fifo_array position for the next replacement only during misses
                if (¬hit) begin
                    fifo_array[index] <= fifo_array[index] + $clog2(NWAYS)'(1);
                end
            end
        end
    end

    assign way_replace = fifo_array[index];

endmodule

output.rtl/caesar_cipher.sv:
module caesar_cipher(
    input_char,
    key,
    output_char
);
    // Check if input_char is an uppercase letter
    if (input_char >= 'A' && input_char <= 'Z') {
        output_char = ('A' + ((input_char - 'A' + key) % 26));
    }
    // Check if input_char is a lowercase letter
    else if (input_char >= 'a' && input_char <= 'z') {
        output_char = ('a' + ((input_char - 'a' + key) % 26));
    }
    // Non-alphabetic characters remain unchanged
    else {
        output_char = input_char;
    }
endmodule

