    // Adder logic
    generate #0
        for (int i = 0; i < NUM_STAGES; i++) begin
            logic [IN_DATA_WIDTH-1:0] sum [IN_DATA_NS >> (i+1)-1:0];
            logic [IN_DATA_WIDTH-1:0] in_a [IN_DATA_NS >> (i+1)-1:0];
