  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first => store LSB in shift_reg_d[0]
            if (EXTRA_BIT == 1)
              shift_reg_d = {parity_bit, p_data_i};  // 9 bits if PARITY!=0
            else
              shift_reg_d = p_data_i;                // 8 bits if PARITY=0
          end
          else begin
            // MSB-first => store MSB in shift_reg_d[SHIFT_W-1]
            // If parity is used, it goes in the LSB or SHIFT_W-1?
            // We'll put it in the LSB if EXTRA_BIT=1
            if (EXTRA_BIT == 1) begin
              shift_reg_d[8:4] = {p_data_i[4:0],parity_bit};
              shift_reg_d[3:0] = p_data_i[8:5];
            end else
              shift_reg_d = p_data_i;
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until SHIFT_W done
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // Done sending SHIFT_W bits
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              if (EXTRA_BIT == 1) begin
                // SHIFT left by 2 bits
                shift_reg_d[SHIFT_W-1:2] = shift_reg_q[SHIFT_W-3:0];
                shift_reg_d[1:0]         = 2'b00;
                count_d                  = count_q + 2;
              end
              else begin
                // Normal MSB-first => shift left by 1
                shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
                count_d     = count_q + 1;
              end
            end
            else begin
              // LSB-first => shift right by 1 (no bug)
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

output.rtl/data_width_converter.sv:
module data_width_converter(
    input wire clock,
    input wire reset,
    input wire [31:0] data_in,
    input wire data_valid,
    output wire [127:0] o_data_out,
    output wire o_data_out_valid
);

    wire [31:0] data_reg1,
    wire [31:0] data_reg2,
    wire [31:0] data_reg3,
    wire [31:0] data_reg4,
    wire [127:0] shifted_data,
    wire [127:0] o_data_out,
    wire [3:0] state,
    wire [3:0] count;

    // State machine
    always_comb begin
        if (reset) begin
            data_reg1 = 0;
            data_reg2 = 0;
            data_reg3 = 0;
            data_reg4 = 0;
            shifted_data = 0;
            o_data_out = 0;
            o_data_out_valid = 0;
            state = 0;
        end else if (data_valid) begin
            if (state == 0) begin
                data_reg1 = data_in;
                state = 1;
            end else if (state == 1) begin
                data_reg2 = data_in;
                state = 2;
            end else if (state == 2) begin
                data_reg3 = data_in;
                state = 3;
            end else if (state == 3) begin
                data_reg4 = data_in;
                state = 0;
                o_data_out_valid = 1;
                count = 0;
            end
        end
    end

    // Shift data
    always clock positive edge begin
        if (state == 0) begin
            shifted_data = data_reg1 << 32;
            shifted_data = (shifted_data << 32) | data_reg2;
            shifted_data = (shifted_data << 32) | data_reg3;
            shifted_data = (shifted_data << 32) | data_reg4;
        end else if (state == 1) begin
            shifted_data = data_reg2 << 32;
            shifted_data = (shifted_data << 32) | data_reg3;
            shifted_data = (shifted_data << 32) | data_reg4;
        end else if (state == 2) begin
            shifted_data = data_reg3 << 32;
            shifted_data = (shifted_data << 32) | data_reg4;
        end else if (state == 3) begin
            o_data_out = shifted_data;
            o_data_out_valid = 1;
            state = 0;
            count = 0;
        end
    end

    // Reset counter
    always clock positive edge begin
        if (reset) begin
            state = 0;
            o_data_out = 0;
            o_data_out_valid = 0;
        end else if (o_data_out_valid) begin
            count = (count + 1) % 4;
        end
    end
endmodule

output.rtl/dbi_enc.sv:
module dbi_enc(
    input data_in,
    input clock,
    input rst_n,
    output data_out,
    output dbi_cntrl
);

    // Initialize previous data
    flip_flop_40 prev_data[40];
    wire [39:0] prev_group1 = {prev_data[39:20]};
    wire [19:0] prev_group0 = {prev_data[19:0]};

    // XOR for each bit in group1
    wire [39:0] xor_group1;
    for (int i = 0; i < 20; i++) {
        xor_group1[i] = data_in[39 - i] ^ prev_group1[i];
    }

    // XOR for each bit in group0
    wire [19:0] xor_group0;
    for (int i = 0; i < 20; i++) {
        xor_group0[i] = data_in[19 - i] ^ prev_group0[i];
    }

    // Full adder for group1
    wire [20:0] sum_group1;
    for (int i = 0; i < 19; i++) {
        full_adder sum_i(.a(xor_group1[i]), .b(xor_group1[i+1]), .c_in(0),
                        .c_out(sum_group1[i+1]));
    }

    // Full adder for group0
    wire [20:0] sum_group0;
    for (int i = 0; i < 19; i++) {
        full_adder sum_i(.a(xor_group0[i]), .b(xor_group0[i+1]), .c_in(0),
                        .c_out(sum_group0[i+1]));
    }

    // Control signals
    dbi_cntrl[1] = sum_group1[20] ? 1 : 0;
    dbi_cntrl[0] = sum_group0[20] ? 1 : 0;

    // Data output
    wire [39:0] data_out;
    data_out = 0;

    // Update data_out
    always @posedge clock begin
        if (!rst_n) begin
            // Shift previous data into data_out
            for (int i = 0; i < 20; i++) {
                data_out[39 - i] = prev_group1[i];
            }
            for (int i = 0; i < 20; i++) {
                data_out[19 - i] = prev_group0[i];
            }
        end
    end

    // Update previous data
    always @posedge clock begin
        prev_group1 = data_out[39:20];
        prev_group0 = data_out[19:0];
    end

    // Initialize flip-flops on reset
    initial begin
        if (rst_n) begin
            $lock $finish;
                prev_group1 = 0;
                prev_group0 = 0;
                $finish;
            end
        end
    end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   input wire rst_n,
   input wire clk,
   input wire [39:0] data_in,
   input wire [1:0] dbi_cntrl,
   output wire [39:0] data_out
);

   // Split data_in into two 20-bit groups
   wire [19:0] group0;
   wire [19:0] group1;

   // Invert groups based on dbi_cntrl
   group0 = data_in[19:0] ^ (dbi_cntrl[0] ? 1:0);
   group1 = data_in[20:39] ^ (dbi_cntrl[1] ? 1:0);

   // Store inverted groups in flip-flops
   flip-flop [19:0] ff_group0, ff_group1;

   // Combine groups to form final data_out
   data_out = (ff_group1 << 20) | ff_group0;

   // Initialize flip-flops on reset
   always @* begin
      if (rst_n) begin
         ff_group0 <= 0;
         ff_group1 <= 0;
      end
   end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module rtl/cvdp_copilot_decode_firstbit (
    input Clk, Rst,
    input In_Data, In_Valid,
    output Out_FirstBit, Out_Found, Out_Valid
);

    // Calculate next power of two for padding
    integer padded_width;
    padded_width = 1;
    while (padded_width < InWidth_g) {
        padded_width = padded_width << 1;
    }

    // Variables for the decoding logic
    integer first_bit;
    integer bit;
    integer i;
    bit valid;
    bit found;
    bit valid_out;
    bit found_out;
    bit first_bit_out;

    // Pipeline registers
    register [padded_width - 1:0] pipeline_reg;
    register [padded_width - 1:0] pipeline_reg_next;

    // Control signals for pipeline stages
    output reg [0:PlRegs_g-1] stage_valid;
    output reg [0:PlRegs_g-1] stage_found;

    // Initialize pipeline registers
    pipeline_reg = (In_Data & In_Valid) ? (In_Data >> (padded_width - 1)) : 0;
    pipeline_reg_next = pipeline_reg;

    // Loop to find the first set bit
    for (i = 0; i < padded_width; i++) {
        bit valid = (In_Data & (1 << i)) & In_Valid;
        bit found = !found;

        if (valid) {
            first_bit = i;
            found = 1;
        }

        // Propagate through pipeline stages
        for (bit = 0; bit < PlRegs_g; bit++) {
            stage_valid[bit] = valid;
            stage_found[bit] = found;
            // Shift the value to the next stage
            if (bit < PlRegs_g - 1) {
                pipeline_reg_next = pipeline_reg;
                pipeline_reg = pipeline_reg_next;
            }
        }

        // Update outputs
        Out_FirstBit = first_bit;
        Out_Found = found;
        Out_Valid = valid;

        // Reset for next iteration
        pipeline_reg = (In_Data & (1 << i)) & In_Valid;
        pipeline_reg_next = pipeline_reg;
    }

    // Reset the pipeline
    if (Rst) {
        pipeline_reg = 0;
        pipeline_reg_next = 0;
        Out_FirstBit = 0;
        Out_Found = 0;
        Out_Valid = 0;
    }

endmodule

