output.rtl/FILO_RTL.sv:
module FILO_RTL(
    parameter DATA_WIDTH,
    parameter FILO_DEPTH,
    input clock,
    input reset,
    input push,
    input pop,
    input [DATA_WIDTH-1:0] data_in,
    output [DATA_WIDTH-1:0] data_out,
    output full,
    output empty
);

    // Internal buffer implementation
    localparam [FILO_DEPTH-1:0] buffer;
    reg top = 0;

    // Initialize on reset
    always_comb begin
        if (reset) begin
            top = 0;
            empty = 1;
            full = 0;
        end
    end

    // Push operation
    alwaysposedge clock begin
        if (push && top < FILO_DEPTH) begin
            buffer[top] = data_in;
            top = top + 1;
            if (top == FILO_DEPTH) full = 1;
            empty = 0;
        end
    end

    // Pop operation
    alwaysposedge clock begin
        if (pop && top > 0) begin
            data_out = buffer[top-1];
            top = top - 1;
            if (top == 0) empty = 1;
            full = 0;
        end
    end

    // Feedthrough case
    alwaysposedge clock begin
        if (push & pop) begin
            data_out = data_in;
            empty = 1;
            full = 0;
        end
    end
endmodule

input.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);


  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            top <= top; 
            data_out <= memory[top-1]; 
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,
    parameter FILO_DEPTH = 16
) (
    input  wire                  clk,
    input  wire                  reset,
    input  wire                  push,
    input  wire                  pop,
    input  wire [DATA_WIDTH-1:0] data_in,
    output reg  [DATA_WIDTH-1:0] data_out,
    output reg                   full,
    output reg                   empty
);

  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];
  reg [$clog2(FILO_DEPTH):0] top;

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;
    else begin
      if (push && pop && empty) begin
        data_out <= data_in;
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin
        if (push && !full) begin
          memory[top] <= data_in;
          top <= top + 1;
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;
            feedthrough_valid <= 0;
          else begin
            top <= top - 1;
            data_out <= memory[top];
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);
    end
  end
endmodule

