module FindFasterClock(
    input  wire clk_A,
    input  wire clk_B,
    input  wire rst_n,            // Active-low reset
    output reg  A_faster_than_B,  // 1 if clk_A is measured faster
    output reg  valid             // 1 once both clocks have measured a period
);

    //----------------------------------------
    // Internal signals
    //----------------------------------------
    reg        measure_B;          
    reg [31:0] b_count;            
    reg [31:0] periodA;            
    reg        done_A;             
    reg        measure_A;
    reg [31:0] a_count;
    reg [31:0] periodB;            
    reg        done_B;

    // A-domain FSM for measuring "periodA"
    reg [1:0] stateA;  
    localparam A_IDLE    = 2'd0,
               A_COUNT   = 2'd1,
               A_DONE    = 2'd2;
    // B-domain FSM for measuring "periodB"
    reg [1:0] stateB;
    localparam B_IDLE    = 2'd0,
               B_COUNT   = 2'd1,
               B_DONE    = 2'd2;

    // Clock A FSM
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            stateA <= A_IDLE;
            measure_B <= 0;
            b_count <= 0;
            periodA <= 0;
            done_A <= 0;
        end else begin
            case (stateA)
                A_IDLE: begin
                    stateA <= A_COUNT;
                end
                A_COUNT: begin
                    if (posedge clk_A) begin
                        a_count <= a_count + 1;
                        stateA <= A_DONE;
                    end
                end
                A_DONE: begin
                    stateA <= A_IDLE;
                end
                default: stateA <= A_IDLE;
            endcase
        end
    end

    // Clock B FSM
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            stateB <= B_IDLE;
            measure_A <= 0;
            a_count <= 0;
            periodB <= 0;
            done_B <= 0;
        end else begin
            case (stateB)
                B_IDLE: begin
                    stateB <= B_COUNT;
                end
                B_COUNT: begin
                    if (posedge clk_B) begin
                        b_count <= b_count + 1;
                        stateB <= B_DONE;
                    end
                end
                B_DONE: begin
                    stateB <= B_IDLE;
                end
                default: stateB <= B_IDLE;
            endcase
        end
    end

    // In B-domain, if measure_B=1, increment b_count on each B rising edge
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            b_count <= 0;
        end else if (measure_B) begin
            b_count <= b_count + 1;
        end
    end

    // In A-domain, if measure_A=1, increment a_count on each A rising edge
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            a_count <= 0;
        end else if (measure_A) begin
            a_count <= a_count + 1;
        end
    end

    // Combine results
    // valid = done_A && done_B
    always @(*) begin
        if (!rst_n) begin
            valid = 0;
            A_faster_than_B = 0;
        end else begin
            valid = (done_A && done_B);
            if (valid) begin
                if (periodB > periodA) begin
                    A_faster_than_B = 1;
                end else begin
                    A_faster_than_B = 0;
                end
            end else begin
                A_faster_than_B = 0;
            end
        end
    end

endmodule

output.rtl/fsm_seq_detector.sv:
enum state_t {
    S0,
    S1,
    S2,
    S3,
    S4,
    S5,
    S6,
    S7
};

reg state_t cur_state, next_state;
reg [7:0] seq_detected_w;

always_comb (
    input logic [2:0] cur_state,
    input logic seq_in
) {
    // State transitions
    if (cur_state == S0) {
        next_state = (seq_in == 1) ? S1 : S0;
    } else if (cur_state == S1) {
        next_state = (seq_in == 0) ? S2 : S1;
    } else if (cur_state == S2) {
        next_state = (seq_in == 1) ? S3 : S2;
    } else if (cur_state == S3) {
        next_state = (seq_in == 1) ? S4 : S3;
    } else if (cur_state == S4) {
        next_state = (seq_in == 0) ? S5 : S4;
    } else if (cur_state == S5) {
        next_state = (seq_in == 0) ? S6 : S5;
    } else if (cur_state == S6) {
        next_state = (seq_in == 0) ? S7 : S6;
    } else if (cur_state == S7) {
        next_state = (seq_in == 1) ? S0 : S7;
    } else {
        next_state = cur_state;
    }
}

always posedge (clk_in or rst_in) begin
    if (rst_in) begin
        cur_state = S0;
        seq_detected_w = 0;
    end else begin
        seq_detected_w = (cur_state == S7);
        next_state = next_state;
        seq_detected = seq_detected_w;
    end
end

