      done_bc_latched    <= 0;
   end else begin
      if(done_ab) begin
         done_ab_latched <= done_ab;
      end else if (go_abc) begin
         done_ab_latched <= 0;
      end

      if(done_bc) begin
         done_bc_latched <= done_bc;
      end else if (go_abc) begin
         done_bc_latched <= 0;
      end
   end
end

assign go_abc = done_ab_latched & done_bc_latched;

endmodule

module gcd_top #(
   parameter WIDTH = 4              // Parameter to define the bit-width of the input and output data
   )(
