module hamming_code_tx_for_4bit( 
  input[3:0] data_in,
  output[7:0] data_out
);
  assign data_out[0] = 1'b0;
  assign data_out[1] = data_in[0] ^ data_in[1] ^ data_in[3]; // 2^0
  assign data_out[2] = data_in[0] ^ data_in[2] ^ data_in[3]; // 2^1
  assign data_out[3] = data_in[0];
  assign data_out[4] = data_in[1] ^ data_in[2] ^ data_in[3]; // 2^2
  assign data_out[5] = data_in[1];
  assign data_out[6] = data_in[2];
  assign data_out[7] = data_in[3];
endmodule

output.rtl/hamming_tx.sv:
module hamming_tx_for_4bit(
  input[3:0] data_in,
  output[7:0] data_out
);

parameters
  DATA_WIDTH = 4;
  PARITY_BIT = 3;

reg [((ENCODED_DATA_BIT) - 1):0] parity[PARITY_BIT:0];
reg [((ENCODED_DATA) - 1):0] data_out;

// Calculate encoded data size and bit-width
ENCODED_DATA = DATA_WIDTH + PARITY_BIT + 1;
ENCODED_DATA_BIT = (ENCODED_DATA - 1).bit_length();

// Data bits positions (excluding parity and redundant bits)
reg data_bits_pos[DATA_WIDTH:0];
integer pos = 3;
for (int i = 0; i < DATA_WIDTH; i++) {
    while (1) {
        if (pos != 0 && (pos & (pos - 1)) != 0) {
            data_bits_pos[i] = pos;
            break;
        }
        pos++;
    }
}

// Assign data_in to data_out
data_out[0] = 0;
for (int i = 0; i < DATA_WIDTH; i++) {
    data_out[data_bits_pos[i]] = data_in[i];
}

// Calculate parity bits
for (int n = 0; n < PARITY_BIT; n++) {
    integer mask = 1 << n;
    reg parity_bit = 0;
    for (int i = 0; i < ENCODED_DATA; i++) {
        if ((i & mask) != 0) {
            parity_bit ^= data_out[i];
        }
    }
    parity[n] = parity_bit;
}

// Assign parity bits to data_out
reg pos_parity[PARITY_BIT:0];
pos_parity[0] = 1;
for (int n = 1; n < PARITY_BIT; n++) {
    pos_parity[n] = pos_parity[n - 1] * 2;
}
for (int n = 0; n < PARITY_BIT; n++) {
    data_out[pos_parity[n]] = parity[n];
}

endmodule

input.rtl/hamming_rx.sv:
module hamming_code_receiver (
  input[7:0] data_in,
  output [3:0] data_out
);

  wire c1,c2,c3,error;
  reg[7:0] correct_data;


  assign c3 =  data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
  assign c2 =  data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
  assign c1 =  data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

  assign error = ({c3,c2,c1}==3'b000) ? 1'b0 : 1'b1;

  always@(*)
  begin
    correct_data = 0;
    if(error)
    begin
      correct_data             = data_in;
      correct_data[{c1,c2,c3}] = ~correct_data[{c1,c2,c3}];
    end
    else
    begin
      correct_data             = data_in;
    end
  end

 assign data_out = {correct_data[7],correct_data[6],correct_data[5],correct_data[3]};

endmodule

input.rtl/hebb_gates.sv:
module hebb_gates(
   input  logic               clk,
   input  logic               rst,
   input  logic               start, // To start the FSM
   input  logic  signed [3:0] a, // First Input
   input  logic  signed [3:0] b, // Second Input
   input  logic         [1:0] gate_select, // To provide the targets for a selected gate in order to train
   output logic  signed [3:0] w1, // Weight 1 obtained by training
   output logic  signed [3:0] w2, // Weight 2 obtained by training
   output logic  signed [3:0] bias,// Bias obtained by training
   output logic [3:0] present_state,// Present State of the Training FSM
   output logic [3:0] next_state // Next_State of the Training FSM

);
   logic signed [3:0] t1;
   logic signed [3:0] t2;
   logic signed [3:0] t3;
   logic signed [3:0] t4;

   gate_target dut(
       .gate_select(gate_select),
       .o_1        (t1),
       .o_2        (t2),
       .o_3        (t3),
       .o_4        (t4)
   );

   localparam [3:0] S0 = 4'd0;
   localparam [3:0] S1 = 4'd1;
   localparam [3:0] S2 = 4'd2;
   localparam [3:0] S3 = 4'd3;
   localparam [3:0] S4 = 4'd4;
   localparam [3:0] S5 = 4'd5;
   localparam [3:0] S6 = 4'd6;
   localparam [3:0] S7 = 4'd7;
   localparam [3:0] S8 = 4'd8;
   localparam [3:0] S9 = 4'd9;
   localparam [3:0] S10 = 4'd10;

   logic [2:0] iteration;
   logic signed [3:0] x1;
   logic signed [3:0] x2;
   logic signed [3:0] delta_w1;
   logic signed [3:0] delta_w2;
   logic signed [3:0] delta_b;
   logic signed [3:0] w1_reg;
   logic signed [3:0] w2_reg;
   logic signed [3:0] bias_reg;
   logic signed [1:0] target;
   logic delta_en;
   logic sum_en;
   logic clr_en;
   logic cap_en;

   always_comb begin
     if(cap_en ) begin
        x1 = a;
        x2 = b;
     end else begin
        x1 = x1 + 4'h0;
        x2 = x2 + 4'h0;
     end

   end

   always_comb begin

     if(delta_en) begin
       delta_w1 = x1 * target;
       delta_w2 = x2 * target;
       delta_b  = target;
     end else begin
       delta_w1 = delta_w1 + 4'h0;
       delta_w2 = delta_w2 + 4'h0;
       delta_b  = delta_b + 4'h0; 
   end

  end

  always_comb begin

     if(sum_en) begin
       w1_reg = w1_reg + delta_w1;
       w2_reg = w2_reg + delta_w2;
       bias_reg = bias_reg + delta_b;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0;
   end
  end

   always_comb begin

     if(clr_en) begin
       w1_reg = 0;
       w2_reg = 0;
       bias_reg = 0;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0; 
    end
   end

   always_ff@(posedge clk or negedge rst) begin
       if(!rst) begin
          present_state <= S0;
          iteration <= 0;
        end else
          present_state <= next_state;
   end

   always_comb begin
        next_state = present_state;

     case(present_state)
             S0  : begin 
                      if(start)
                         next_state = S1;
                      else
                         next_state = S0;
                   end
             S1  : begin 
                         next_state = S2;
                   end
             S2  : begin 
                      if(iteration == 0)
                        next_state = S3;
                     else if(iteration == 1)
                        next_state = S4;
                     else if(iteration == 2)
                        next_state = S5;
                     else 
                        next_state = S6;
                   end
             S3  : begin 
                         next_state = S7;

                   end
             S4  : begin 
                         next_state = S7;
                  end
             S5  : begin 
