module interrupt_controller 
#(
    parameter NUM_INTERRUPTS = 4, 
    parameter ADDR_WIDTH = 8)
(
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    input  logic                      cpu_ack,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,
    input  logic [NUM_INTERRUPTS-1:0] priority_map_value [NUM_INTERRUPTS-1:0],
    input  logic                      priority_map_update,
    input  logic [ADDR_WIDTH-1:0]     vector_table_value [NUM_INTERRUPTS-1:0],
    input  logic                      vector_table_update,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_mask_value,
    input  logic                      interrupt_mask_update
);

    // Initialize default priority map and vector table
    logic [NUM_INTERRUPTS-1:0] priority_map = {3,2,1,0};
    logic [NUM_INTERRUPTS-1:0] vector_table = {12,8,4,0};
    logic [NUM_INTERRUPTS-1:0] interrupt_mask = 15; // All interrupts active by default

    logic [NUM_INTERRUPTS-1:0] pending_interrupts;
    logic [NUM_INTERRUPTS-1:0] busy;
    logic [NUM_INTERRUPTS-1:0] current_interrupt;

    // Always active logic
    always logic
    begin
        // Initialize on first clock cycle
        if (rst_n) begin
            pending_interrupts = 0;
            busy = 0;
            current_interrupt = 0;
        end

        // Process interrupts
        if (!busy) begin
            // Check interrupts in order of priority (lowest first)
            for (int i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
                if ((pending_interrupts & (1 << i)) && (interrupt_mask[i] == 1)) begin
                    // Service this interrupt
                    interrupt_service = (1 << i);
                    cpu_interrupt = 1;
                    pending_interrupts = pending_interrupts ^ (1 << i);
                    interrupt_mask = interrupt_mask ^ (1 << i);
                    current_interrupt = i;
                    busy = 1;
                    break;
                end
            end
        end

        // Wait for CPU acknowledgment
        while (cpu_ack) begin
            // Clear service signals and reset state
            interrupt_service = 0;
            cpu_interrupt = 0;
            pending_interrupts = 0;
            interrupt_mask = 15;
            busy = 0;
            current_interrupt = 0;
        end
    end

    // Handle dynamic updates
    always logic
    begin
        // Only update if we're not busy
        if (!busy) begin
            // Update priority map
            if (priority_map_update) begin
                priority_map = priority_map_value;
            end
            // Update vector table
            if (vector_table_update) begin
                vector_table = vector_table_value;
            end
            // Update interrupt mask
            if (interrupt_mask_update) begin
                interrupt_mask = interrupt_mask_value;
            end
        end
    end
endmodule

output.rtl/pic_starvation_prevention.sv:
module interrupt_controller (
    input wire clk,
    input wire rst_n,
    input wire reset_interrupts,
    input wire [9:0] interrupt_requests,
    input wire interrupt_ack,
    input wire interrupt_trig,
    input wire [3:0] priority_override,
    input wire [3:0] override_interrupt_id,
    input wire priority_override_en,
    output reg [3:0] interrupt_id,
    output reg interrupt_valid,
    output reg [9:0] interrupt_status,
    output reg [9:0] missed_interrupts,
    output reg starvation_detected
);

    parameter STARVATION_THRESHOLD = 5;

    localparam [2:0] 
        IDLE = 3'b000,
        PRIORITY_CALC = 3'b001,
        SERVICE_PREP = 3'b010,
        SERVICING = 3'b011,
        COMPLETION = 3'b100,
        ERROR = 3'b111;

    reg [2:0] current_state, next_state;
    reg [9:0] pending_interrupts;
    reg [3:0] wait_counters [0:9];
    reg [4:0] effective_priority [0:9];
    reg [3:0] active_mask;
    reg [3:0] service_timer;
    reg timeout_error;
    reg [3:0] next_interrupt_id;
    reg [4:0] max_priority;

    always @(posedge clk or negedge rst_n or negedge reset_interrupts) begin
        if (rst_n & reset_interrupts) begin
            // Reset all states and clear error
            pending_interrupts = 0;
            wait_counters = 0;
            effective_priority = 0;
            active_mask = 0;
            service_timer = 0;
            timeout_error = 0;
            next_interrupt_id = 0;
            max_priority = 0;
            current_state = IDLE;
        end else if (rst_n) begin
            // Reset pending interrupts and clear error
            pending_interrupts = 0;
            wait_counters = 0;
            effective_priority = 0;
            active_mask = 0;
            service_timer = 0;
            timeout_error = 0;
            next_interrupt_id = 0;
            max_priority = 0;
            current_state = IDLE;
        end else begin
            case (current_state)
                IDLE: begin
                    // Check if any interrupts are pending
                    if (pending_interrupts != 0) begin
                        // Calculate effective priority
                        effective_priority = priority_override;
                        for (int i = 0; i < 10; i++) begin
                            if ((active_mask & (1 << i)) != 0) begin
                                effective_priority[i] = priority_override;
                            end else begin
                                effective_priority[i] = wait_counters[i] + 1;
                            end
                        end
                        // Select highest priority interrupt
                        next_interrupt_id = 0;
                        max_priority = effective_priority[0];
                        for (int i = 1; i < 10; i++) begin
                            if (effective_priority[i] > max_priority) begin
                                max_priority = effective_priority[i];
                                next_interrupt_id = i;
                            end
                        end
                        current_state = PRIORITY_CALC;
                    end
                PRIORITY_CALC: begin
                    // Check if any interrupts are pending
                    if (pending_interrupts != 0) begin
                        // Apply priority override if enabled
                        if (priority_override_en & (priority_override[0] != 0)) begin
                            effective_priority = priority_override;
                            next_interrupt_id = priority_override[1];
                            max_priority = priority_override[2];
                        end else begin
                            // Select highest priority interrupt
                            next_interrupt_id = 0;
                            max_priority = effective_priority[0];
                            for (int i = 1; i < 10; i++) begin
                                if (effective_priority[i] > max_priority) begin
                                    max_priority = effective_priority[i];
                                    next_interrupt_id = i;
                                end
                            end
                        end
                        current_state = SERVICE_PREP;
                    end
                PRIORITY_CALC: default begin
                    // No pending interrupts
                    current_state = IDLE;
                end
            endcase
        end
    end

    always @(posedge clk) begin
        case (current_state)
            IDLE: begin
                // Check if any interrupts are pending
                if (pending_interrupts != 0) begin
                    // Calculate effective priority
                    effective_priority = priority_override;
                    for (int i = 0; i < 10; i++) begin
                        if ((active_mask & (1 << i)) != 0) begin
                            effective_priority[i] = priority_override;
                        end else begin
                            effective_priority[i] = wait_counters[i] + 1;
                        end
                    end
                    // Select highest priority interrupt
                    next_interrupt_id = 0;
                    max_priority = effective_priority[0];
                    for (int i = 1; i < 10; i++) begin
                        if (effective_priority[i] > max_priority) begin
                            max_priority = effective_priority[i];
                            next_interrupt_id = i;
                        end
                    end
                    // Prepare to service selected interrupt
                    next_state = SERVICING;
                    next_interrupt_id = next_interrupt_id;
                    next_state = SERVICING;
                end
                current_state = IDLE;
            end
            SERVICING: begin
                // Service the selected interrupt
                if (interrupt_mask & (1 << next_interrupt_id)) begin
                    // Check if timeout occurred
                    if (service_timer >= STARVATION_THRESHOLD) begin
                        // Update status and clear error
                        if (starvation_detected) begin
                            // Restore previous status
                            interrupt_status = previous_interrupt_status;
                        end
                        // Set valid bit and reset timer
                        interrupt_valid = 1;
                        service_timer = 0;
                        next_state = COMPLETION;
                    end else begin
                        // Restore previous status
                        interrupt_status = previous_interrupt_status;
                        next_state = COMPLETION;
                    end
                end else begin
                    // Timeout occurred
                    next_state = COMPLETION;
                    if (timeout_error) begin
                        // Restore previous status
                        interrupt_status = previous_interrupt_status;
                        // Clear error
                        timeout_error = 0;
                    end
                end
            end
            COMPLETION: begin
                // Update status and clear error
                if (starvation_detected) begin
                    // Restore previous status
                    interrupt_status = previous_interrupt_status;
                end
                // Clear the serviced interrupt
                next_state = IDLE;
                current_state = IDLE;
            end
            ERROR: begin
                // Clear all pending interrupts
                pending_interrupts = 0;
                // Restore previous status
                interrupt_status = previous_interrupt_status;
                // Clear error
                timeout_error = 0;
                // Reset state
                next_state = IDLE;
                current_state = IDLE;
            end
        endcase
    end

    // Initialize previous state values
    always begin
        previous_interrupt_status = interrupt_status;
    end

endmodule

output.rtl/interrupt_controller_apb.sv:
// SystemVerilog RTL for a Priority-Based Interrupt Controller with APB Interface

module interrupt_controller_apb #(
    parameter NUM_INTERRUPTS = 4,
    parameter ADDR_WIDTH = 8
    )
    (
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    input  logic                      cpu_ack,
    output  logic [$clog2(NUM_INTERRUPTS)-1:0] interrupt_idx,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,

    // APB Interface Signals
    input  logic                      pclk,
    input  logic                      presetn,
    input  logic                      psel,
    input  logic                      penable,
    input  logic                      pwrite,
    input  logic [ADDR_WIDTH-1:0]     paddr,
    input  logic [31:0]               pwdata,
    output logic [31:0]               prdata,
    output logic                      pready
);

    logic [NUM_INTERRUPTS-1:0] interrupt_mask;
    logic servicing;
    logic [NUM_INTERRUPTS-1:0] pending_interrupts;

    // Initialize on reset
    begin
        if (rst_n) begin
            // Reset all registers
            pending_interrupts = 0;
            interrupt_mask = (1 << NUM_INTERRUPTS) - 1;
            vector_table = 0;
            // Initialize priority map
            for (logic i = 0; i < NUM_INTERRUPTS; i++) begin
                priority_map[i] = i;
            end
            servicing = 0;
            pready = 0;
        end
    end

    // Process interrupt requests
    always logic clock_edge #+1 begin
        if (rst_n) begin
            pending_interrupts = 0;
            servicing = 0;
            pready = 0;
        end
        else if (interrupt_requests) begin
            pending_interrupts = pending_interrupts | ((1 << interrupt_requests) - 1);
        end

        // Select highest priority interrupt
        if (serving) begin
            // Find highest set bit in pending_interrupts
            interrupt_idx = 0;
            for (logic i = 0; i < NUM_INTERRUPTS; i++) begin
                if (pending_interrupts & (1 << i)) begin
                    interrupt_idx = i;
                    break;
                end
            end

            // Prepare for APB communication
            if (interrupt_idx != -1) begin
                // Set APB signals
                psel = 1;
                penable = 1;
                pwrite = 1;
                paddr = vector_table[interrupt_idx];
                prdata = 0;

                // Send vector address to APB
                pwrite = 1;
                pclk = 1;
                pready = 1;
                pwrite = 0;
            end else begin
                // No pending interrupts
                pready = 0;
            end
        end

        // Update pending_interrupts
        pending_interrupts = pending_interrupts ^ (1 << interrupt_idx);
    end

    // Cleanup
    always logic clock_edge #+1 begin
        if (pready) begin
            servicing = 0;
            pready = 0;
        end
    end

output.rtl/ir_receiver.sv:
module ir_receiver (
    input  logic        reset_in,       // Active HIGH reset
    input  logic        clk_in,         // System clock (100 KHz, 10us)
    input  logic        ir_signal_in,   // Input signal (IR)
    output logic [11:0] ir_frame_out,   // Decoded 12-bit frame
    output logic        ir_frame_valid  // Indicates validity of the decoded frame
);

    typedef enum logic [1:0] {idle, start, decoding, finish} ir_state;
    ir_state present_state, next_state;

    logic started; 
    logic decoded; 
    logic failed; 
    logic success;

    logic [11:0] ir_frame_reg; 
    logic stored;
    reg cycle_counter;
    reg bit_counter;

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                started = false;
                bit_counter = 0;
                ir_frame_reg = 0;
                next_state = start;
            end

            start: begin
                if (ir_signal_in & 1 && !bit_counter) begin
                    // Valid start bit transition
                    started = true;
                    bit_counter = 0;
                    next_state = decoding;
                end
                else
                    next_state = idle;
                end

            decoding: begin
                if (bit_counter < 12) begin
                    if (ir_signal_in & 1) begin
                        ir_frame_reg = ir_frame_reg + 1;
                        bit_counter = bit_counter + 1;
                        next_state = decoding;
                    end
                else
                    // All bits captured, check validity
                    if (bit_counter == 12) begin
                        success = true;
                        next_state = finish;
                    else begin
                        // Bit timing invalid
                        success = false;
                        failed = true;
                        next_state = idle;
                    end
                end
            end

            finish: begin
                // Output latency: 1 clock cycle
                ir_frame_valid = 1;
                next_state = idle;
            end
        end
    end

    // Store the final frame
    always @* begin
        stored = ir_frame_reg;
    end

    // Output the stored frame
    ir_frame_out = stored;
endmodule

module ir_receiver (
    input  logic        reset_in,               // Active HIGH reset
    input  logic        clk_in,                 // System clock (10 KHz, 100us)
    input  logic        ir_signal_in,           // Input signal (IR)
    output logic [6:0]  ir_function_code_out,   // Decoded output for different functions
    output logic [4:0]  ir_device_address_out,  // "00001": TV, "00010":HDMI1, "00100":USB, "01000":HDMI2, "10000": VCR
    output logic        ir_output_valid         // Indicates validity of the decoded frame
);

    typedef enum logic [2:0] {idle, start, decoding, finish, frame_space} ir_state;
    ir_state present_state, next_state;

    logic started;
    logic decoded;
    logic failed;
    logic success;
    logic frame_full;
    logic ir_frame_valid;

    logic [11:0] ir_frame_reg;
    logic [11:0] ir_frame_out;
    logic stored;

    logic frame_space_counter;
    logic bit_counter;

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                if (ir_signal_in == 1 && started == 0)
                    next_state = start;
                else
                    next_state = idle;
            end
            start: begin
                if (ir_signal_in == 0 && started == 1)
                    next_state = decoding;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = start;
            end
            decoding: begin
                if (bit_counter == 12 && ir_frame_valid == 1)
                    next_state = finish;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = decoding;
            end
            finish: begin
                if (success == 1)
                    next_state = frame_space;
                    bit_counter = 0;
                    frame_full = 1;
                    ir_frame_valid = 1;
                else
                    next_state = finish;
            end
            frame_space: begin
                if (frame_full == 1)
                    frame_full = 0;
                    frame_space_counter = 0;
                    next_state = idle;
                else
                    frame_space_counter++;
                    next_state = frame_space;
                    if (frame_space_counter == 45)
                        next_state = idle;
            end
        end
    end

    // Bit decoding logic
    logic [11:0] current_bit;
    logic bit_value;

    always_comb begin
        case (present_state)
            idle: current_bit = 0;
            start: current_bit = 0;
            decoding: begin
                current_bit = ir_signal_in;
                if (current_bit == 1) begin
                    // 0 is LOW pulse of 0.6ms, 1 is LOW pulse of 1.2ms
                    ir_frame_reg[bit_counter] = current_bit;
                    bit_counter++;
                end
            end
            finish: begin
                ir_frame_out = ir_frame_reg;
                success = 1;
                ir_output_valid = 1;
            end
        end
    end

    // Function and address decoding
    always_comb begin
        case (ir_frame_out)
            12'b001000010110: ir_function_code_out = 7'b1111111;
            12'b000000010000: ir_function_code_out = 7'b0011111;
            // ... (add all function/address mappings)
        end
    end

