    input  logic     [ 1:0]      ex_if_type_i,          // Data type: 0x2 (word), 0x1 (halfword), 0x0 (byte)
    input  logic     [31:0]      ex_if_wdata_i,         // Data to write to memory
    input  logic     [31:0]      ex_if_addr_base_i,     // Base address
    input  logic     [31:0]      ex_if_addr_offset_i,   // Offset address
    input  logic                 ex_if_extend_mode_i,
    output logic                 ex_if_ready_o    ,


    // Writeback stage interface
    output logic     [31:0]      wb_if_rdata_o,         // Requested data
    output logic                 wb_if_rvalid_o,        // Requested data valid

    // Data memory (DMEM) interface
    output logic                 dmem_req_o,
    input  logic                 dmem_gnt_i,
    output logic     [31:0]      dmem_req_addr_o,
    output logic                 dmem_req_we_o,
    output logic     [ 3:0]      dmem_req_be_o,
    output logic     [31:0]      dmem_req_wdata_o,
    input  logic     [31:0]      dmem_rsp_rdata_i,
    input  logic                 dmem_rvalid_i
    );

  // Internal signals
  logic ex_req_fire;
  logic dmem_req_we_q;
  logic [31:0] data_addr_int;
  logic misaligned_addr;
  logic [3:0] dmem_be, dmem_req_be_q;

  logic busy_q;  
  logic dmem_req_q ;




  logic [31:0] dmem_req_wdata_q;
  logic [31:0] dmem_req_addr_q;

  logic [31:0] wb_if_rdata_q;
  logic wb_if_rvalid_q;

  logic [1:0] rdata_offset_q ;
  logic [31:0] rdata_w_ext , rdata_h_ext, rdata_b_ext, data_rdata_ext ;
  logic [1:0] data_type_q ;
  logic data_sign_ext_q ;

  assign data_addr_int = ex_if_addr_base_i + ex_if_addr_offset_i;

  assign ex_req_fire = ex_if_req_i && !busy_q && !misaligned_addr;
  assign ex_if_ready_o = !busy_q;


  always_comb begin
    misaligned_addr = 1'b0;
    dmem_be = 4'b0000;
    case (ex_if_type_i)  
      2'b00: begin  
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0001;
            2'b01:   dmem_be = 4'b0010;
            2'b10:   dmem_be = 4'b0100;
            2'b11:   dmem_be = 4'b1000;
            default: dmem_be = 4'b0000;
          endcase
      end

      2'b01: begin  
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0011;
            2'b10:   dmem_be = 4'b1100;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end

      2'b10: begin  
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b1111;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end
      default: begin
          dmem_be = 4'b0000;
          misaligned_addr = 1'b1;
      end 
    endcase
  end


  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      dmem_req_q <= 1'b0;
      dmem_req_addr_q <= '0;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
      rdata_offset_q <= '0 ;
    end else if (ex_req_fire) begin
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= ex_if_we_i;
      dmem_req_be_q <= dmem_be ;
      dmem_req_wdata_q <= ex_if_wdata_i ; 

      rdata_offset_q <= data_addr_int[1:0] ; 
      data_sign_ext_q <= ex_if_extend_mode_i ;
      data_type_q <= ex_if_type_i ;
    end else if (dmem_req_q && dmem_gnt_i) begin
      dmem_req_q <= 1'b0;  
      dmem_req_addr_q <= '0 ;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
    end
  end



  always_comb begin
    case (rdata_offset_q)
      2'b00: rdata_w_ext = dmem_rsp_rdata_i[31:0];
      default: rdata_w_ext = '0 ;
    endcase
  end

  always_comb begin
    case (rdata_offset_q)
      2'b00: begin
        if (data_sign_ext_q) rdata_h_ext ={{16{dmem_rsp_rdata_i[15]}}, dmem_rsp_rdata_i[15:0]};
        else rdata_h_ext =  {16'h0000, dmem_rsp_rdata_i[15:0]};
      end

      2'b10: begin
        if (data_sign_ext_q) rdata_h_ext = {{16{dmem_rsp_rdata_i[31]}}, dmem_rsp_rdata_i[31:16]};
        else rdata_h_ext = {16'h0000, dmem_rsp_rdata_i[31:16]}; 
      end

      default: begin
        rdata_h_ext = '0 ;  
      end
    endcase  
  end

  always_comb begin
    case (rdata_offset_q)
      2'b00: begin
        if (data_sign_ext_q) rdata_b_ext  = {{24{dmem_rsp_rdata_i[7]}}, dmem_rsp_rdata_i[7:0]}; 
        else rdata_b_ext = {24'h00_0000, dmem_rsp_rdata_i[7:0]};
      end

      2'b01: begin
        if (data_sign_ext_q) rdata_b_ext  = {{24{dmem_rsp_rdata_i[15]}}, dmem_rsp_rdata_i[15:8]}; 
        else rdata_b_ext = {24'h00_0000, dmem_rsp_rdata_i[15:8]};
      end

      2'b10: begin
        if (data_sign_ext_q) rdata_b_ext  = {{24{dmem_rsp_rdata_i[23]}}, dmem_rsp_rdata_i[23:16]}; 
        else rdata_b_ext = {24'h00_0000, dmem_rsp_rdata_i[23:16]};
      end

      2'b11: begin
        if (data_sign_ext_q) rdata_b_ext  = {{24{dmem_rsp_rdata_i[31]}}, dmem_rsp_rdata_i[31:24]}; 
        else rdata_b_ext = {24'h00_0000, dmem_rsp_rdata_i[31:24]};
      end
    endcase  
  end

  always_comb begin
    case (data_type_q)
      2'b00:        data_rdata_ext = rdata_b_ext ;
      2'b01:        data_rdata_ext = rdata_h_ext;
      2'b10:        data_rdata_ext = rdata_w_ext;
      default:      data_rdata_ext = 32'b0;
    endcase  
  end


  always_comb begin : dmem_req
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      wb_if_rdata_q   <= 32'b0;
      wb_if_rvalid_q  <= 1'b0;
    end else if (dmem_rvalid_i) begin
      wb_if_rdata_q   <= data_rdata_ext;
      wb_if_rvalid_q  <= 1'b1;
    end else begin
      wb_if_rvalid_q  <= 1'b0;
    end
  end

  assign wb_if_rdata_o =  wb_if_rdata_q;
  assign wb_if_rvalid_o = wb_if_rvalid_q;

  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      busy_q <= 1'b0;
    end else if (ex_req_fire) begin
      busy_q <= 1'b1;
    end else if (dmem_req_we_q && dmem_gnt_i) begin
      busy_q <= 1'b0;  
    end else if (!dmem_req_we_q && dmem_rvalid_i) begin
      busy_q <= 1'b0;  
    end
  end

endmodule

output.rtl/load_store_unit.sv:
module load_store_unit (
    input  logic                 clk,
    input  logic                 rst_n,

    // EX stage interface
    input  logic                 ex_if_req_i,           // LSU request
    input  logic                 ex_if_we_i,            // Write enable: 0 (load), 1 (store)
    input  logic     [ 1:0]      ex_if_type_i,          // Data type: 0x2 (word), 0x1 (halfword), 0x0 (byte)
    input  logic     [31:0]      ex_if_wdata_i,         // Data to write to memory
    input  logic     [31:0]      ex_if_addr_base_i,     // Base address
    input  logic     [31:0]      ex_if_addr_offset_i,   // Offset address
    input  logic     [31:0]      ex_if_extend_mode_i,
    output logic                 ex_if_ready_o,

    // Writeback stage interface
    output logic     [31:0]      wb_if_rdata_o,         // Requested data
    output logic                 wb_if_rvalid_o,        // Requested data valid

    // Data memory (DMEM) interface
    output logic                 dmem_req_o,
    input  logic                 dmem_gnt_i,
    output logic     [31:0]      dmem_req_addr_o,
    output logic                 dmem_req_we_o,
    output logic     [31:0]      dmem_req_be_o,
    output logic     [31:0]      dmem_req_wdata_o,
    input  logic     [31:0]      dmem_rsp_rdata_i,
    input  logic                 dmem_rvalid_i
);

  // Internal signals
  logic ex_req_fire;
  logic dmem_req_we_q;
  logic [31:0] data_addr_int;
  logic misaligned_addr;
  logic [31:0] dmem_be, dmem_req_be_q;

  logic busy_q;  
  logic dmem_req_q ;

  // FSM states
  logic state;
  // State descriptions:
  // IDLE: Default state where the LSU waits for a request from the execute stage.
  // ALIGNED_WR: Handles single bus transaction for an aligned store.
  // ALIGNED_RD: Handles single bus transaction for an aligned load.
  // MISALIGNED_WR: Initiates the first bus transaction for a misaligned store.
  // MISALIGNED_RD: Initiates the first bus transaction for a misaligned load.
  // MISALIGNED_WR_1: Completes the second bus transaction for a misaligned store.
  // MISALIGNED_RD_GNT: Waits for the first data response (dmem_rvalid_i) for misaligned RD.
  // MISALIGNED_RD_1: Completes the second bus transaction for a misaligned load.
  // MISALIGNED_RD_GNT_1: Waits for the second data response (dmem_rvalid_i) for misaligned RD.

  always_comb begin
    misaligned_addr = 1'b0;
    dmem_be = 4'b0000;
    case (ex_if_type_i)  
      2'b00: begin  
          case (data_addr_int[1:0])
            2'b00: dmem_be = 4'b0001;
            2'b10: dmem_be = 4'b0010;
            default: dmem_be = 4'b0000;
            misaligned_addr = 1'b1;
          endcase
      end

      2'b01: begin  
          case (data_addr_int[1:0])
            2'b00: dmem_be = 4'b0011;
            2'b10: dmem_be = 4'b1100;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end

      2'b10: begin  
          case (data_addr_int[1:0])
            2'b00: dmem_be = 4'b1111;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end
      default: begin
          dmem_be = 4'b0000;
          misaligned_addr = 1'b1;
      end 
    endcase
  end

  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      dmem_req_q <= 1'b0;
      dmem_req_addr_q <= '0;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
      state <= IDLE;
    end else if (ex_req_fire) begin
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= ex_if_we_i;
      dmem_req_be_q <= dmem_be ;
      dmem_req_wdata_q <= ex_if_wdata_i ; 
      state <= ALIGNED_WR;
    end else if (dmem_req_q && dmem_gnt_i) begin
      dmem_req_q <= 1'b0;  
      dmem_req_addr_q <= '0 ;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
      state <= IDLE;
    end
  end

  always_comb begin : dmem_req
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      wb_if_rdata_q   <= 32'b0;
      wb_if_rvalid_q  <= 1'b0;
      state <= IDLE;
    end else if (ex_if_type_i == 2 && !dmem_req_we_q && !misaligned_addr) begin
      // Word write
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= ex_if_wdata_i;
      state <= MISALIGNED_WR;
    end else if (ex_if_type_i == 1 && !dmem_req_we_q && !misaligned_addr) begin
      // Halfword write
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= ex_if_wdata_i;
      state <= MISALIGNED_WR_1;
    end else if (ex_if_type_i == 0 && !dmem_req_we_q && !misaligned_addr) begin
      // Byte write
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= ex_if_wdata_i;
      state <= MISALIGNED_WR_1;
    end else if (ex_if_type_i == 2 && dmem_req_we_q && dmem_gnt_i) begin
      // Word read
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= dmem_rsp_rdata_i;
      state <= MISALIGNED_RD;
    end else if (ex_if_type_i == 1 && dmem_req_we_q && dmem_gnt_i) begin
      // Halfword read
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= dmem_rsp_rdata_i;
      state <= MISALIGNED_RD_GNT;
    end else if (ex_if_type_i == 0 && dmem_req_we_q && dmem_gnt_i) begin
      // Byte read
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= dmem_rsp_rdata_i;
      state <= MISALIGNED_RD_GNT;
    end else if (dmem_req_q && !dmem_gnt_i) begin
      // Bus idle
      state <= IDLE;
    end
  end

  always_comb begin
    case (state)  
      of (IDLE)  
        break;
      of (ALIGNED_WR)  
        break;
      of (ALIGNED_RD)  
        break;
      of (MISALIGNED_WR)  
        state <= MISALIGNED_WR_1;
      of (MISALIGNED_WR_1)  
        state <= IDLE;
      of (MISALIGNED_RD)  
        state <= MISALIGNED_RD_GNT;
      of (MISALIGNED_RD_GNT)  
        state <= MISALIGNED_RD_1;
      of (MISALIGNED_RD_1)  
        state <= IDLE;
      endcase
  end

  always_comb begin : dmem_req
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      busy_q <= 1'b0;
    end else if (ex_if_type_i == 2 && !dmem_req_we_q && !misaligned_addr) begin
      // Word store
      busy_q <= 1'b1;
    end else if (ex_if_type_i == 1 && !dmem_req_we_q && !misaligned_addr) begin
      // Halfword store
      busy_q <= 1'b1;
    end else if (ex_if_type_i == 0 && !dmem_req_we_q && !misaligned_addr) begin
      // Byte store
      busy_q <= 1'b1;
    end else if (dmem_req_q && !dmem_gnt_i) begin
      // Bus idle
      busy_q <= 1'b0;
    end
  end

  always_comb begin
    case (data_type_q)  
      2'b00: data_rdata_ext = rdata_b_ext ;
      2'b01: data_rdata_ext = rdata_h_ext;
      2'b10: data_rdata_ext = rdata_w_ext;
      default: data_rdata_ext = 32'b0;
    endcase  
  end

  always_comb begin : dmem
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      wb_if_rdata_q   <= 32'b0;
      wb_if_rvalid_q  <= 1'b0;
    end else if (ex_if_type_i == 2 && !dmem_req_we_q && !misaligned_addr) begin
      // Word write
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= ex_if_wdata_i;
      busy_q <= 1'b1;
      state <= MISALIGNED_WR;
    end else if (ex_if_type_i == 1 && !dmem_req_we_q && !misaligned_addr) begin
      // Halfword write
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= ex_if_wdata_i;
      busy_q <= 1'b1;
      state <= MISALIGNED_WR_1;
    end else if (ex_if_type_i == 0 && !dmem_req_we_q && !misaligned_addr) begin
      // Byte write
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= ex_if_wdata_i;
      busy_q <= 1'b1;
      state <= MISALIGNED_WR_1;
    end else if (ex_if_type_i == 2 && dmem_req_we_q && dmem_gnt_i) begin
      // Word read
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= dmem_rsp_rdata_i;
      busy_q <= 1'b0;
      state <= MISALIGNED_RD;
    end else if (ex_if_type_i == 1 && dmem_req_we_q && dmem_gnt_i) begin
      // Halfword read
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= dmem_rsp_rdata_i;
      busy_q <= 1'b0;
      state <= MISALIGNED_RD_GNT;
    end else if (ex_if_type_i == 0 && dmem_req_we_q && dmem_gnt_i) begin
      // Byte read
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= 1'b1;
      dmem_req_be_q <= dmem_be;
      dmem_req_wdata_q <= dmem_rsp_rdata_i;
      busy_q <= 1'b0;
      state <= MISALIGNED_RD_GNT;
    end else if (dmem_req_q && !dmem_gnt_i) begin
      // Bus idle
      busy_q <= 1'b0;
      state <= IDLE;
    end
  end
  // End of FSM
  always_comb begin : dmem
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

input.rtl/manchester_encoder.sv:
// Manchester encoder module
module manchester_encoder #(
    parameter N = 8  // Default width of input data
) (
    input  logic clk_in,          // Clock input
    input  logic rst_in,          // Active high reset input
    input  logic enc_valid_in,        // Input valid signal
    input  logic [N-1:0] enc_data_in, // N-bit input data
    output logic enc_valid_out,       // Output valid signal
    output logic [2*N-1:0] enc_data_out // 2N-bit output encoded data
);

    // Internal register to hold the encoded data
    logic [2*N-1:0] encoded_data;

    // Combinational logic to generate Manchester encoded data
    always_comb begin
        if (enc_valid_in) begin
            for (int i = 0; i < N; i++) begin
                if (enc_data_in[i] == 1'b1) begin
                    enc_data_out[2*i] = 1'b1;
                    enc_data_out[2*i + 1] = 1'b0;
                end else begin
                    enc_data_out[2*i] = 1'b0;
                    enc_data_out[2*i + 1] = 1'b1;
                end
            end
            enc_valid_out = 1'b1; // Set the valid signal
        end else begin
            enc_valid_out = 1'b0; // Clear the valid signal if no valid input
        end
    end

endmodule

input.rtl/top_manchester.sv:
// Top Module integrating Encoder & decoder
module top_manchester #(
    parameter N = 8  // Default width of input and output data
) (
    input  logic clk_in,          // Clock input
    input  logic rst_in,          // Active high reset input
    // Encoder Signals
    input  logic enc_valid_in,        // Input valid signal
    input  logic [N-1:0] enc_data_in, // N-bit input data
    output logic enc_valid_out,       // output valid signal
    output logic [2*N-1:0] enc_data_out, // 2*N-bit encoder output data

    // Decoder Signals
    input  logic dec_valid_in,        // Input valid signal
