                data_out[5*DATA_WIDTH/8 + i] = data_in[3*DATA_WIDTH/4-1-i]; 
                data_out[3*DATA_WIDTH/4 + i] = data_in[7*DATA_WIDTH/8-1-i]; 
                data_out[7*DATA_WIDTH/8 + i] = data_in[DATA_WIDTH-1-i];     
            end
            data_out[DATA_WIDTH] = parity_bit; 
        end
        default: begin
            data_out = data_in;	
            data_out[DATA_WIDTH] = parity_bit; 					                        
        end
    endcase
end

endmodule

