module password_generator #(
    parameter WIDTH = 4  
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];  
  logic [7:0] counter;  
  logic [1:0] char_type; 

  integer i;

  always@(posedge clk or posedge reset) begin
    if (reset) begin
      counter = 0;
      char_array = {WIDTH{0}}; // Initialize all zeros
    end else
      counter = (counter + 1) % 256;

      for (i = 0; i < WIDTH; i = i + 1) begin
        case (char_type)
          0b00: char_array[i] = ((counter + char_array[(i+1)%WIDTH]) % 26) + 8'h97;
          0b01: char_array[i] = ((counter + i) % 26) + 8'h65;
          0b10: char_array[i] = ((counter + char_array[(i+WIDTH-1)%WIDTH]) % 14) + 8'h33;
          0b11: char_array[i] = ((counter + i) % 10) + 8'h48;
        endcase
      end
  end

  // Pack char_array into password
  integer j;
  for (j = 0; j < WIDTH; j = j + 1) begin
    password[(j*8)+7] = char_array[j] & 8'h0F;
    password[(j*8)+6] = (char_array[j] >> 4) & 8'h0F;
    password[(j*8)+5] = (char_array[j] >> 8) & 8'h0F;
    password[(j*8)+4] = (char_array[j] >> 12) & 8'h0F;
    password[(j*8)+3] = (char_array[j] >> 16) & 8'h0F;
    password[(j*8)+2] = (char_array[j] >> 20) & 8'h0F;
    password[(j*8)+1] = (char_array[j] >> 24) & 8'h0F;
    password[(j*8)+0] = char_array[j] & 8'h0F;
  end
endmodule

output.rtl/perceptron_gates.sv:
module perceptron_gates (
    input clock,
    input rst_n,
    input [3:0] x1,
    input [3:0] x2,
    input learning_rate,
    input [3:0] threshold,
    input [1:0] gate_select,
    output [3:0] percep_w1,
    output [3:0] percep_w2,
    output [3:0] percep_bias,
    output [1] stop,
    output [3:0] input_index,
    output [3:0] y_in,
    output [3:0] y
);

// Microcode ROM definition
reg [4:0] microcode_rom = 6'd0000;

// Microcode sequence
always @posedge clock begin
    case (microcode_rom)
        0: // Initialize weights and bias to zero
            percep_w1 <= 4'd0;
            percep_w2 <= 4'd0;
            percep_bias <= 4'd0;
            present_addr <= 4'd0;
            y_in <= 4'd0;
            y <= 4'd0;
            input_index <= 3'd0;
            microcode_rom <= (present_addr + 1) & 0xF;
            stop <= 0;
        1: // Compute perceptron output
            y_in <= (x1 * percep_w1) + (x2 * percep_w2) + percep_bias;
            y <= (y_in >= 0) ? 4'd1 : -4'd1;
            input_index <= 3'd0;
            microcode_rom <= (present_addr + 1) & 0xF;
            stop <= 0;
        2: // Select target based on gate type and input_index
            case (gate_select)
                2'b00: // AND gate
                    target_0 <= 4'd1;
                    target_1 <= 4'd1;
                    target_2 <= 4'd1;
                    target_3 <= 4'd1;
                2'b01: // OR gate
                    target_0 <= 4'd1;
                    target_1 <= 4'd1;
                    target_2 <= 4'd1;
                    target_3 <= -4'd1;
                2'b10: // NAND gate
                    target_0 <= 4'd1;
                    target_1 <= 4'd1;
                    target_2 <= 4'd1;
                    target_3 <= -4'd1;
                2'b11: // NOR gate
                    target_0 <= 4'd1;
                    target_1 <= -4'd1;
                    target_2 <= -4'd1;
                    target_3 <= -4'd1;
            endcase
            present_addr <= present_addr + 1;
            microcode_rom <= (present_addr + 1) & 0xF;
            stop <= 0;
        3: // Update weights and bias if needed
            case (present_addr)
                4'd0: // Initial update
                    wt1_update <= learning_rate * x1;
                    wt2_update <= learning_rate * x2;
                    bias_update <= learning_rate;
                4'd1: // Subsequent updates
                    wt1_update <= 4'd0;
                    wt2_update <= 4'd0;
                    bias_update <= 4'd0;
                default: // No update
                    wt1_update <= 4'd0;
                    wt2_update <= 4'd0;
                    bias_update <= 4'd0;
            endcase
            percep_w1 <= percep_w1 + wt1_update;
            percep_w2 <= percep_w2 + wt2_update;
            percep_bias <= percep_bias + bias_update;
            input_index <= input_index + 1;
            if (input_index >= 4) input_index <= 3'd0;
            microcode_rom <= (present_addr + 1) & 0xF;
            stop <= 0;
        4: // Check for convergence
            case (present_addr)
                4'd0: // Check after first update
                    if (percep_w1 == prev_percep_wt_1 &&
                        percep_w2 == prev_percep_wt_2 &&
                        percep_bias == prev_percep_bias) {
                        stop <= 1;
                    }
                    present_addr <= 4'd0;
                default: // Continue training
                    present_addr <= present_addr + 1;
            endcase
            microcode_rom <= (present_addr + 1) & 0xF;
            stop <= 0;
        default: // Unknown instruction
            percep_w1 <= 4'd0;
            percep_w2 <= 4'd0;
            percep_bias <= 4'd0;
            present_addr <= 4'd0;
            y_in <= 4'd0;
            y <= 4'd0;
            input_index <= 3'd0;
            microcode_rom <= (present_addr + 1) & 0xF;
            stop <= 0;
    endcase
endmodule

input.rtl/perceptron_gates.sv:
module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic learning_rate, // Learning rate (alpha)
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
);

   logic [15:0] microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;


   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   initial begin 
      microcode_rom[0] = 16'b0001_0000_0000_0000; 
      microcode_rom[1] = 16'b0010_0001_0000_0000; 
      microcode_rom[2] = 16'b0011_0010_0000_0000; 
      microcode_rom[3] = 16'b0100_0011_0000_0000; 
      microcode_rom[4] = 16'b0101_0100_0000_0000; 
      microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end  

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      next_addr        = microinstruction[15:12];
      train_action     = microinstruction[11:8];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case (train_action)
         4'd0:  begin 
                   percep_wt_1_reg = 4'd0;
                   percep_wt_2_reg = 4'd0;
                   percep_bias_reg = 4'd0;
                   stop = 1'b0;
                   next_addr = next_addr + 4'd0;
                   y_in = 4'd0;
                   y    = 4'd0;
                   prev_wt1_update = 4'd0;
                   prev_wt2_update = 4'd0;
                   prev_bias_update = 4'd0;
                   input_index = 0;
                   target = 0;
                   wt1_update = 0;
                   wt2_update = 0;
                   bias_update = 0;
                   epoch_counter = 0;
                end
         4'd1 : begin 
                   y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg); 
                   if (y_in > threshold)
                      y = 4'd1;
                   else if (y_in >= -threshold && y_in <= threshold)
                      y = 4'd0;
                   else
                      y = -4'd1;

                   percep_wt_1_reg  = percep_wt_1_reg  + 4'd0;
                   percep_wt_2_reg  = percep_wt_2_reg  + 4'd0;
                   percep_bias_reg  = percep_bias_reg  + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
