module copilot_rs_232 (
    clock,
    reset_neg,
    tx_datain_ready,
    Present_Processing_Completed,
    tx_datain,
    tx_transmitter,
    tx_transmitter_valid
);
    // Parameters
    parameter HIGH = 1'b1;
    parameter LOW = 1'b0;
    parameter CLOCK_FREQ = 100000000; // 100MHz
    parameter BAUD_RATE = 115200;     // Default baud rate
    parameter REG_INPUT = 1;
    parameter BAUD_ACC_WIDTH = 16;

    // Inputs
    input reset_neg;
    input clock;
    input tx_datain_ready;
    input Present_Processing_Completed;
    input [7:0] tx_datain;

    // Outputs
    output tx_transmitter;
    output tx_transmitter_valid;

    // Internal signals
    reg tx_transmitter;
    reg state; // 4-bit state machine
    reg baud_acc;
    wire [BAUD_ACC_WIDTH:0] baud_inc;
    wire MuxBit;
    wire tx_transmitter_valid_gf;

    // Instantiate the Baud Rate Generator
    baud_rate_generator #(
        .BAUD_ACC_WIDTH(BAUD_ACC_WIDTH),
        .CLOCK_FREQ(CLOCK_FREQ),
        .BAUD_RATE(BAUD_RATE)
    ) baud_gen (
        .clock(clock),
        .reset_neg(reset_neg),
        .enable(tx_transmitter_valid),
        .baud_pulse(baud_pulse)
    );

    // State Machine
    always @ (posedge clock or negedge reset_neg) begin
        if (reset_neg == LOW) begin
            state = 0; // Idle state
            tx_transmitter = LOW;
        end else if (tx_datain_ready == HIGH && Present_Processing_Completed == LOW) begin
            state = 1; // Start state
            tx_transmitter = LOW;
        end else if (state < 4) begin
            case (state)
                1: tx_transmitter = HIGH; // Start bit
                2: tx_transmitter = tx_datain[6]; // Data bit 0
                3: tx_transmitter = tx_datain[5]; // Data bit 1
                4: tx_transmitter = tx_datain[4]; // Data bit 2
                5: tx_transmitter = tx_datain[3]; // Data bit 3
                6: tx_transmitter = tx_datain[2]; // Data bit 4
                7: tx_transmitter = tx_datain[1]; // Data bit 5
                8: tx_transmitter = tx_datain[0]; // Data bit 6
                9: tx_transmitter = HIGH; // Data bit 7
            endcase
            state +== 1;
        end else if (state == 10) begin
            tx_transmitter = HIGH; // Stop bit
            state = 0;
        end
    end

    // Output Multiplexer
    always @ (posedge clock or negedge reset_neg) begin
        if (reset_neg == LOW) begin
            tx_transmitter_valid = LOW;
        end else if (Present_Processing_Completed == HIGH) begin
            tx_transmitter_valid = HIGH;
        end else begin
            tx_transmitter_valid = MuxBit;
        end
    end
endmodule

// Baud Rate Generator Module
module baud_rate_generator #(
    parameter CLOCK_FREQ = 100000000, // 100MHz
    parameter BAUD_RATE = 115200, // Default baud rate
    parameter BAUD_ACC_WIDTH = 16
)
 (
    input clock,
    input reset_neg,
    input enable,
    output reg baud_pulse
);

    // Internal signals
    wire [BAUD_ACC_WIDTH:0] baud_inc;
    reg [BAUD_ACC_WIDTH:0] baud_acc;

    // Calculate the baud increment value
    assign baud_inc = ((BAUD_RATE << (BAUD_ACC_WIDTH - 4)) + (CLOCK_FREQ >> 5)) / (CLOCK_FREQ >> 4);

    // Baud rate generator logic
    always @ (posedge clock or negedge reset_neg) begin
        if (enable) begin
            baud_acc = 0;
            baud_pulse = 0;
        end else begin
            baud_acc = baud_acc + baud_inc;
            baud_pulse = 1;
        end
    end
endmodule

