output.rtl/sdram_controller.sv:
module sdram_controller (clk, reset, addr, data_in, data_out, read, write, sdram_clk, sdram_cke, sdram_cs, sdram_ras, sdram_cas, sdram_we, sdram_addr, sdram_ba, sdram_dq, dq_out);

// State control parameters
parameter states = 6;
parameter busy = 0;

// FSM states: INIT, IDLE, ACTIVATE, READ, WRITE, REFRESH
enum states FSM = 0 # INIT, 1 # IDLE, 2 # ACTIVATE, 3 # READ, 4 # WRITE, 5 # REFRESH;

// Local variables
reg [23:0] addr_reg;
reg [15:0] data_in_reg, data_out_reg;
reg read_reg, write_reg;
reg [1:0] state = FSM'INIT;
reg busy_flag = busy;

always @ (posedge clk or posedge reset) begin
    case(state)
        FSM'INIT:
            // Initialization sequence
            busy_flag = 1;
            #10;
            state = FSM'IDLE;
            break;
        FSM'IDLE:
            if (read_reg == 1 || write_reg == 1) begin
                state = FSM'ACTIVATE;
                busy_flag = 1;
            end else if ( busy_flag == 0 ) begin
                // Auto-refresh after 1024 cycles
                busy_flag = 1;
                #1024;
                state = FSM'REFRESH;
                break;
            end
            break;
        FSM'ACTIVATE:
            if (read_reg == 1) begin
                state = FSM'READ';
                busy_flag = 1;
            end else if (write_reg == 1) begin
                state = FSM'WRITE';
                busy_flag = 1;
            end else if ( busy_flag == 0 ) begin
                // Transition to IDLE after activation
                state = FSM'IDLE;
                busy_flag = 0;
            end
            break;
        FSM'READ:
            // Read operation
            // Activate row and column addresses
            // Process read operation
            busy_flag = 1;
            // Wait for read operation completion
            state = FSM'IDLE;
            busy_flag = 0;
            break;
        FSM'WRITE:
            // Write operation
            // Activate row and column addresses
            // Process write operation
            busy_flag = 1;
            // Wait for write operation completion
            state = FSM'IDLE;
            busy_flag = 0;
            break;
        FSM'REFRESH:
            // Refresh operation
            // Activate row and column addresses
            // Refresh SDRAM content
            busy_flag = 1;
            // Wait for refresh operation completion
            state = FSM'IDLE;
            busy_flag = 0;
            break;
    endcase
end

// Output data
data_out_reg = data_in_reg;

// Connect SDRAM inputs/outputs
sdram_clk = addr_reg[22];
sdram_cke = addr_reg[21];
sdram_cs = addr_reg[20];
sdram_ras = addr_reg[19];
sdram_cas = addr_reg[18];
sdram_we = addr_reg[17];
sdram_addr = addr_reg[16];
sdram_ba = addr_reg[15];
sdram_dq = addr_reg[14:0];
dq_out = data_out_reg;

// Address register
always @ (posedge addr or posedge reset) begin
    addr_reg = addr;
    // Shift in new address bits
    addr_reg = (addr_reg << 1) | (addr[22] & ~(1<<22));
end

endmodule

output.rtl/secure_read_write_bus_interface.v:
parameter p_configurable_key = 8'hAA;
parameter p_data_width = 8;
parameter p_addr_width = 8;

module secure_read_write_bus_interface(
    input wire p_addr_width i_addr,
    input wire p_data_width i_data_in,
    input wire 8 i_key_in,
    input wire 1 i_read_write_enable,
    input wire 1 i_capture_pulse,
    input wire 1 i_reset_bar,
    output wire p_data_width o_data_out,
    output wire 1 o_error
) {
    wire reg [p_addr_width-1:0] addr;
    wire reg [p_data_width-1:0] data;
    reg [1] state = 0; // 0: idle, 1: read, 2: write
    reg [1] is_error = 0;

    always @posedge i_capture_pulse begin
        if (i_reset_bar) begin
            state = 0;
            o_error = 0;
            o_data_out = 0;
            addr = 0;
            data = 0;
            continue;
        end

        if (i_read_write_enable) begin
            state = 1;
        end else begin
            state = 2;
        end

        if (state == 1) begin // Read operation
            if (i_key_in != p_configurable_key) begin
                o_error = 1;
                o_data_out = 0;
                addr = 0;
                data = 0;
                continue;
            end
            if (i_addr >= 0 && i_addr < (1 << p_addr_width)) begin
                addr = i_addr;
                data = i_data_in;
            else begin
                o_error = 1;
                o_data_out = 0;
                continue;
            end
        end else if (state == 2) begin // Write operation
            if (i_key_in != p_configurable_key) begin
                o_error = 1;
                o_data_out = 0;
                addr = 0;
                data = 0;
                continue;
            end
            if (i_addr >= 0 && i_addr < (1 << p_addr_width)) begin
                data = i_data_in;
                addr = i_addr;
            else begin
                o_error = 1;
                o_data_out = 0;
                continue;
            end
        end

        o_data_out = data;
        o_error = is_error;
    end
}

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank(
    parameter p_address_width = 8,
    parameter p_data_width = 8,
    parameter p_unlock_code_0 = 0xAB,
    parameter p_unlock_code_1 = 0xCD
);

    // State variables
    reg state = 0; // 0: locked, 1: waiting for code0, 2: waiting for code1, 3: unlocked
    reg [p_address_width-1:0] address;

    // Unlock code storage
    reg [p_data_width-1:0] unlock_code_0 = p_unlock_code_0;
    reg [p_data_width-1:0] unlock_code_1 = p_unlock_code_1;

    // Inputs
    input [p_address_width-1:0] i_addr;
    input [p_data_width-1:0] i_data_in;
    input i_read_write_enable;
    input i_capture_pulse;
    input i_rst_n;

    // Outputs
    output [p_data_width-1:0] o_data_out;

    // State transitions
    always @(posedge i_capture_pulse) begin
        case (state)
            0: 
                // Check if write operation to address 0 or 1
                if (i_read_write_enable == 0) begin
                    if (i_addr == 0) begin
                        if (i_data_in == unlock_code_0) begin
                            state = 1;
                        end else begin
                            state = 0;
                        end
                    end else if (i_addr == 1) begin
                        if (i_data_in == unlock_code_1) begin
                            state = 1;
                        end else begin
                            state = 0;
                        end
                    end else begin
                        // Other addresses are locked
                        state = 0;
                    end
                end else begin
                    // Read operation
                    if (i_addr == 0 || i_addr == 1) begin
                        o_data_out = 0;
                    else begin
                        o_data_out = 0;
                    end
                end
            1: 
                // Waiting for code0
                if (i_read_write_enable == 0) begin
                    if (i_addr == 0) begin
                        if (i_data_in == unlock_code_0) begin
                            state = 2;
                        end else begin
                            state = 0;
                        end
                    end else begin
                        state = 0;
                    end
                end else begin
                    o_data_out = 0;
                end
            2: 
                // Waiting for code1
                if (i_read_write_enable == 0) begin
                    if (i_addr == 1) begin
                        if (i_data_in == unlock_code_1) begin
                            state = 3;
                        end else begin
                            state = 0;
                        end
                    end else begin
                        state = 0;
                    end
                end else begin
                    o_data_out = 0;
                end
            3: 
                // Unlocked
                o_data_out = i_data_in;
            default:
                state = 0;
        endcase
    end

    // Output data
    assign o_data_out = (state == 3) ? i_data_in : 0;

    // Reset handling
    always @* begin
        if (i_rst_n) begin
            state = 0;
            address = 0;
            unlock_code_0 = 0;
            unlock_code_1 = 0;
        end
    end

    // Encode address
    always @* begin
        address = i_addr;
    end

    // Encode data
    always @* begin
        if (state == 3) begin
            if (i_read_write_enable == 0) begin
                o_data_out = i_data_in;
            else begin
                o_data_out = 0;
            end
        else begin
            o_data_out = 0;
        end
    end
endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    // Internal state variable
    reg state;                  // 0:Idle, 1:Configure Delay, 2:Counting, 3:Done

    // Internal registers
    reg [3:0] delay;            // Holds the 4-bit delay value

    // State transitions
    always @(i_rst_n, i_data_in, o_processing, o_completed) begin
        case(state)
            0: // Idle state
                if (i_rst_n) begin
                    state = 0;
                    // Reset all states on reset
                    // Begin searching for 1101 pattern
                    data_reg = 0;
                    state = 1;
                end
                // If 1101 is detected, transition to Configure Delay state
                if (i_data_in) begin
                    data_reg = 3;
                    state = 1;
                end
            1: // Configure Delay state
                if (i_rst_n) begin
                    state = 0;
                end
                // Read next 4 bits as delay value
                delay = data_reg;
                data_reg = 0;
                state = 2;
            2: // Counting state
                if (i_rst_n) begin
                    state = 0;
                end
                o_processing = 1;
                // Count for (delay + 1) * 1000 clock cycles
                // o_time_left starts at delay and decrements by 1 every 1000 cycles
                o_time_left = delay;
                data_reg = (data_reg + 1) % 16;
                state = 2;
                o_time_left = o_time_left - 1;
                if (data_reg == 15) begin
                    o_completed = 1;
                    state = 3;
                end
            3: // Done state
                if (i_ack) begin
                    state = 0;
                end
        endcase
    end

    // Initializations
    initial begin
        state = 0;
        data_reg = 0;
    end

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
module binary_to_one_hot_decoder_sequencial (
    parameter BINARY_WIDTH,
    parameter OUTPUT_WIDTH,
    input i_binary_in,
    input i_clk,
    input i_rstb,
    output o_one_hot_out
);

    reg [OUTPUT_WIDTH - 1: 0] one_hot_out;

    always clocked (
        i_clk
    ) begin
        if (i_rstb)
            one_hot_out = 0;
        else
            for (int j = 0; j < BINARY_WIDTH; j++) begin
                one_hot_out[j] = (i_binary_in >> j) & 1;
            end
        end
    end

    o_one_hot_out = one_hot_out;
endmodule

