output.rtl/signedadder.v:
module signedadder #(parameter DATA_WIDTH = 8)(
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);
    reg o_state; // State control
    reg [DATA_WIDTH-1:0] a, b; // Operand registers
    reg [DATA_WIDTH-1:0] sum; // Intermediate sum

    // Reset handling
    always @(i_rst_n) begin
        if (i_rst_n) begin
            o_state = 0; // IDLE state
            o_ready = 0;
            o_overflow = 0;
            a = 0;
            b = 0;
        end
    end

    // Load state
    always @(i_start, i_enable) begin
        if (i_enable && !i_rst_n && !o_state) begin
            a = i_operand_a;
            b = i_operand_b;
            o_state = 1; // LOAD state
        end
    end

    // Compute state
    always @(i_mode) begin
        if (o_state == 1) begin
            if (i_mode == 0) begin // Add
                sum = a + b;
            else begin // Subtract
                sum = a - b;
            end
            o_state = 2; // COMPUTE state
        end
    end

    // Output state
    always @(i_clk) begin
        if (o_state == 2) begin
            // Overflow detection
            reg sign_a, sign_b, sign_sum;
            sign_a = (a >> (DATA_WIDTH-1)) & 1;
            sign_b = (b >> (DATA_WIDTH-1)) & 1;
            sign_sum = (sum >> (DATA_WIDTH-1)) & 1;

            o_overflow = 0;
            if ((sign_a & sign_b) != sign_sum) begin
                o_overflow = 1;
            end

            o_resultant_sum = sum;
            o_ready = 1;
            o_state = 3; // OUTPUT state
        end
    end

    // Clear operation
    always @(i_clear) begin
        if (i_clear) begin
            o_resultant_sum = 0;
            o_overflow = 0;
            o_ready = 0;
            o_state = 0; // IDLE state
        end
    end
endmodule

output.rtl/spi_fsm.v:
module spi_fsm (
    input  wire         i_clk,       // System clock
    input  wire         i_rst_b,     // Active-low async reset
    input  wire [15:0]  i_data_in,   // Parallel 16-bit data to transmit
    input  wire         i_enable,    // Enable block
    input  wire         i_fault,     // Fault indicator
    input  wire         i_clear,     // Forces FSM to clear/idle

    output reg          o_spi_cs_b,  // SPI chip select (active-low)
    output reg          o_spi_clk,   // SPI clock
    output reg          o_spi_data,  // Serialized SPI data out
    output reg [4:0]    o_bits_left, // Bits left to transmit
    output reg          o_done,      // Single-cycle pulse when done or error
    output reg [1:0]    o_fsm_state  // FSM state for external monitoring
);

    reg fsm_state = 0; // Idle state (00)

    always @* begin
        if (i_rst_b) begin
            fsm_state = 0; // Idle
            o_spi_cs_b = 1;
            o_spi_clk = 0;
            o_spi_data = 0;
            o_bits_left = 16;
            o_done = 0;
            o_fsm_state = 0;
        end else if (i_enable) begin
            case (fsm_state)
                0: begin // Idle
                    o_spi_cs_b = 0;
                    o_spi_clk = 0;
                    o_spi_data = 0;
                    o_bits_left = 16;
                    fsm_state = 1; // Transmit
                end
                1: begin // Transmit
                    o_spi_cs_b = 0;
                    o_spi_data = (i_data_in[15]);
                    o_bits_left = 15;
                    fsm_state = 2; // Clock Toggle
                    o_spi_clk = 1;
                end
                2: begin // Clock Toggle
                    o_spi_data = o_spi_data & 1;
                    o_bits_left = o_bits_left - 1;
                    fsm_state = (o_bits_left == 0) ? 0 : 3;
                    o_spi_clk = ~o_spi_clk;
                end
                3: begin // Error
                    o_spi_cs_b = 1;
                    o_spi_clk = 0;
                    o_spi_data = 0;
                    o_bits_left = 10;
                    fsm_state = 3;
                end
            endcase
        end else if (i_fault) begin
            fsm_state = 3; // Error
            o_spi_cs_b = 1;
            o_spi_clk = 0;
            o_spi_data = 0;
            o_bits_left = 10;
            o_fsm_state = 3;
        end else if (i_clear) begin
            fsm_state = 0; // Idle
            o_spi_cs_b = 1;
            o_spi_clk = 0;
            o_spi_data = 0;
            o_bits_left = 16;
            o_fsm_state = 0;
        end
    end

    // Set done when transmitting is complete
    if (o_bits_left == 0 && fsm_state == 0) begin
        o_done = 1;
    else
        o_done = 0;
    end

    // Set done when error state
    if (fsm_state == 3) begin
        o_done = 1;
    end

    // Set done when in Done state
    if (o_fsm_state == 2) begin
        o_done = 1;
    end

endmodule

