                                // We found the spot
                                insert_phase <= 0;
                                next_state <= 0;
                            end
                        end

                        default: next_state <= 0;
                    endcase
                end

                DONE: begin
                    // Sorting complete, output the result
                    done <= 1;
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end
            endcase
        end
    end

    // Insertion sort phases for each i
    // 0: Initialize key and j
