module square_root_seq #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,
    input  wire clock,
    input  wire rst,
    input  wire start,
    output reg [WIDTH/2-1:0] final_root,
    output reg done
);
    reg [WIDTH-1:0] remainder, square_root;
    reg [WIDTH/2-1:0] odd;
    reg state;
    integer i;

    always @posedge clock begin
        if (rst) begin
            state = IDLE;
            remainder = num;
            square_root = 0;
            odd = 1;
        end else if (start) begin
            state = IDLE;
            remainder = num;
            square_root = 0;
            odd = 1;
        end else if (state == IDLE && !start) begin
            state = IDLE;
        end else if (state == IDLE) begin
            remainder = num;
            square_root = 0;
            odd = 1;
            state = COMPUTE;
        end else if (state == COMPUTE) begin
            if (remainder >= odd) begin
                remainder = remainder - odd;
                square_root = square_root + 1;
                odd = odd + 2;
                state = COMPUTE;
            end else begin
                done = 1;
                state = IDLE;
            end
        end
    end
endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict(
    input [31:0] fetch_rdata_i,
    input [31:0] fetch_pc_i,
    input 1     fetch_valid_i,
    output 1     predict_branch_taken_o,
    output [31:0] predict_branch_pc_o
);

    // Extract immediate value from instruction
    input [31:0] imm_b_type, imm_cj_type, imm_cb_type;

    // Determine instruction type
    localparam OPCODE_BRANCH = 7'h63;
    localparam OPCODE_JAL = 7'h6F;
    localparam OPCODE_JALR = 7'h67;

    // Always predict jumps as taken
    if ((fetch_rdata_i[31:28] == OPCODE_JAL) || (fetch_rdata_i[31:28] == OPCODE_JALR) || 
        (fetch_rdata_i[31:28] == OPCODE_JAL) || (fetch_rdata_i[31:28] == OPCODE_JALR)) {
        predict_branch_taken_o = 1;
        predict_branch_pc_o = fetch_pc_i + imm_b_type;
    }

    // For branch instructions, predict based on immediate sign
    else if (fetch_rdata_i[31:28] == OPCODE_BRANCH) {
        if (imm_b_type[31] == 1) {
            predict_branch_taken_o = 1;
            predict_branch_pc_o = fetch_pc_i + imm_b_type;
        } else {
            predict_branch_taken_o = 0;
            predict_branch_pc_o = fetch_pc_i + imm_b_type;
        }
    }

    // Other instructions not predicted
    else {
        predict_branch_taken_o = 0;
        predict_branch_pc_o = fetch_pc_i + imm_b_type;
    }
endmodule

