module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,
  output logic [8:0]  predict_confidence_o,
  output logic [1:0]  predict_exception_o,
  output logic [2:0]  predict_branch_type_o,
  output logic [31:0] predict_branch_offset_o);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;
  logic [3:2] inst_type;

  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:25], instr[11:8], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0 };

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign inst_type = case(instr[6:0])
    6'b000000 -> 3'b000;
    6'b000001 -> 3'b001;
    6'b000010 -> 3'b010;
    6'b000011 -> 3'b011;
    6'b000100 -> 3'b100;
    default -> 3'b101;
  endcase;

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase

    predict_confidence_o = 8'd0;
    predict_exception_o = 1'b0;
    predict_branch_taken_o = 1'b0;
    predict_branch_type_o = 3'b000;

    local reg [31:0] target_address;

    if (fetch_valid_i) begin
      case (fetch_pc_i[1:0])
        00 -> predict_exception_o = 1'b1;
      endcase

      if (instr_jal || instr_jalr || instr_b) begin
        case (imm_b_type[31])
          1'b1 -> predict_confidence_o = 8'd90;
          1'b0 -> predict_confidence_o = 8'd50;
        endcase
        predict_branch_taken_o = (instr_jal || instr_jalr || instr_b);
        predict_branch_type_o = inst_type;
        target_address = fetch_pc_i + branch_imm;
        predict_branch_pc_o = target_address;
      elsif (instr_cj || instr_cb) begin
        case (imm_cb_type[31])
          1'b1 -> predict_confidence_o = 8'd90;
          1'b0 -> predict_confidence_o = 8'd50;
        endcase
        predict_branch_taken_o = (instr_cj || instr_cb);
        predict_branch_type_o = inst_type;
        target_address = fetch_pc_i + branch_imm;
        predict_branch_pc_o = target_address;
      else begin
        predict_confidence_o = 8'd0;
        predict_branch_taken_o = 1'b0;
        predict_branch_type_o = inst_type;
      endelse
    end
  end
  assign predict_branch_pc_o = target_address;
endmodule

module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;
  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;
  logic instr_b_taken;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  // Determine branch type and set branch_taken
  instr_jal = (instr[6:0] == 7'h6F);
  instr_jalr = (instr[6:0] == 7'h67);
  instr_b = (instr[6:0] == 7'h63);
  instr_cj = (instr[5:0] & 7'h0F) == 7'h08;
  instr_cb = (instr[5:0] & 7'h0F) == 7'h0C;

  instr_b_taken = (instr_b & (imm_b_type[31] == 1)) 
                | (instr_cb & (imm_cb_type[31] == 1));

  // Select branch_imm based on instruction type
  branch_imm = 0;
  if (instr_jal) branch_imm = imm_jal_type;
  else if (instr_jalr) branch_imm = imm_jalr_type;
  else if (instr_b) branch_imm = imm_b_type;
  else if (instr_cj) branch_imm = imm_cj_type;
  else if (instr_cb) branch_imm = imm_cb_type;
  else branch_imm = 0;

  // Set prediction outputs
  predict_branch_taken_o = 
    instr_jal | instr_jalr | instr_cj | instr_b_taken;
  predict_branch_pc_o = predict_branch_taken_o ? (fetch_pc_i + branch_imm) : fetch_pc_i;

module static_branch_predict(
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,

  // Additional outputs
  output logic [7:0]  predict_confidence_o,   // Confidence level in prediction
  output logic        predict_exception_o,    // Exception/misalignment detection
  output logic [2:0]  predict_branch_type_o,  // Type of branch
  output logic [31:0] predict_branch_offset_o // Calculated branch offset
);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;
  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  // Decode instruction
  instr = fetch_rdata_i;

  // Determine instruction type
  instr_jal = (instr[6:0] == 7'h6f);
  instr_jalr = (instr[6:0] == 7'h67);
  instr_b = (instr[6:0] == 7'h63);
  instr_cj = (instr[6:0] & 0x18) != 0;
  instr_cb = (instr[6:0] & 0x10) != 0;

  // Calculate imms based on instruction type
  if (instr_jal) {
    imm_jal_type = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  else if (instr_jalr) {
    imm_jalr_type = { {20{instr[31]}}, instr[31:20] } + reg_addr;
  else if (instr_b) {
    imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
  else if (instr_cj) {
    imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0 };
  else if (instr_cb) {
    imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0 };
  }

  // Determine branch type and confidence
  if (instr_jal || instr_jalr) {
    predict_branch_type_o = 8'b00001001;
    predict_confidence_o = 100;
  else if (instr_b) {
    predict_branch_type_o = 8'b00000010;
    if (imm_b_type[31] == 1) {
      predict_confidence_o = 90;
    else {
      predict_confidence_o = 50;
    }
  else if (instr_cj || instr_cb) {
    predict_branch_type_o = 8'b00000001;
    if (imm_cj_type[31] == 1 || imm_cb_type[31] == 1) {
      predict_confidence_o = 90;
    else {
      predict_confidence_o = 50;
    }

  // Set exception flag if instruction is invalid
  if (!fetch_valid_i) {
    predict_exception_o = 1;
    predict_confidence_o = 0;
  }

  // Calculate predicted branch taken flag
  predict_branch_taken_o = (predict_confidence_o > 50);

  // Calculate predicted branch target address
  predict_branch_offset_o = 0;
  if (instr_jal) {
    predict_branch_offset_o = imm_jal_type;
  else if (instr_jalr) {
    predict_branch_offset_o = imm_jalr_type;
  else if (instr_b) {
    predict_branch_offset_o = imm_b_type;
  else if (instr_cj || instr_cb) {
    if (instr_cj) {
      predict_branch_offset_o = imm_cj_type;
    else {
      predict_branch_offset_o = imm_cb_type;
    }
  }

  // Add PC offset to current PC to get predicted target address
  predict_branch_pc_o = fetch_pc_i + predict_branch_offset_o;

