`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/swizzler.sv:
module swizzler #(
    parameter int N = 8
)(
    input  logic_clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [N-1:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M : j*M + M - 1];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:N-1] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] > N)
            //            temp_error_flag = 1'b1;
            // Now: if (map_idx[i] >= N)
            if (map_idx[i] >= N)
                temp_error_flag = 1'b1;
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= processed_swizzle_data;
                3'b001: operation_reg <= processed_swizzle_data;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= processed_swizzle_data[N-1-i];
                3'b011: operation_reg <= {processed_swizzle_data[N/2-1:0], processed_swizzle_data[N-1:N/2]};
                3'b100: operation_reg <= ~processed_swizzle_data;
                3'b101: operation_reg <= {processed_swizzle_data[N-2:0], processed_swizzle_data[N-1:N-2]};
                default: operation_reg <= processed_swizzle_data;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            data_out <= operation_reg[N-1-i];
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
);
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
);
  input clock;
  input reset;
  input write_en;
  input read_en;
  input data_in;
  output empty;
  output full;
  output data_out;

  // Configuration parameters
  parameter FIFO_DEPTH = 2**ADDR_WIDTH;
  integer pointer = 0;

  // FIFO array
  array<int, DATA_WIDTH> fifo_FIFO = {0} * FIFO_DEPTH;

  // Initial block
  initial begin
    if (reset) begin
      pointer = 0;
      fifo_FIFO = {0};
      empty = 1;
      full = 0;
    end
  end

  // Write operation
  always @posedge clock begin
    if (write_en) begin
      if (pointer < FIFO_DEPTH) begin
        fifo_FIFO[pointer] = data_in;
        pointer = pointer + 1;
        if (pointer > FIFO_DEPTH) begin
          full = 1;
        end
      end
    end
  end

  // Read operation
  always @posedge clock begin
    if (read_en) begin
      if (pointer > 0) begin
        data_out = fifo_FIFO[pointer];
        pointer = pointer - 1;
        if (pointer < 0) begin
          empty = 1;
        end
      end
    end
  end
endmodule

module sync_lifo #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
)(
    input wire clock,
    input wire reset,
    input wire write_en,
    input wire read_en,
    input wire [DATA_WIDTH-1:0] data_in,
    output wire error,
    output wire valid,
    output [DATA_WIDTH-1:0] data_out
);

    localparam DEPTH = (1 << ADDR_WIDTH);
    reg [DEPTH-1:0] ptr;
    reg [DEPTH-1:0] lifo_counter;
    reg [DATA_WIDTH-1:0] memory [DEPTH-1:0];
    reg [DATA_WIDTH-1:0] temp_data_out;
    integer i;

    assign empty = (lifo_counter == 0) ? 1'b1 : 1'b0;
    assign full  = (lifo_counter == DEPTH) ? 1'b1 : 1'b0;

    integer error_flag = 0;

    always @(posedge clock) begin
        if (reset) begin
            lifo_counter <= 0;
            ptr <= {ADDR_WIDTH {1'b0}};
        end else if (!full && write_en) begin
            lifo_counter <= lifo_counter + 1;
            ptr <= ptr + 1;
        end else if (!empty && read_en) begin
            lifo_counter <= lifo_counter - 1;
            ptr <= ptr - 1;
        end
    end

    always @(posedge clock) begin
        if (reset) begin
            ptr <= {ADDR_WIDTH {1'b0}};
            temp_data_out <= {DATA_WIDTH {1'b0}};
        end else if (write_en && !full) begin
            memory[ptr] <= data_in;
            ptr <= ptr + 1;
        end else if (read_en && !empty) begin
            temp_data_out <= memory[ptr - 1];
            ptr <= ptr - 1;
            if (error_flag) begin
                error = 1;
                valid = 0;
            else
                valid = 1;
            end
        end
    end

    assign data_out = temp_data_out;
endmodule

output.rtl/sync_serial_communication_top.sv:
module sync_serial_communication_top (
    input clock,
    input reset_n,
    input data_in,
    input sel
);

    // Transmitter block
    tx_block tx(
        clock = clock,
        reset_n = reset_n,
        data_in = data_in,
        sel = sel
    );

    // Receiver block
    rx_block rx(
        clock = clock,
        reset_n = reset_n,
        data_in = serial_out,
        sel = sel
    );

    // Connect outputs
    data_out = data_out;
    done = done;

endmodule

module tx_block (
    input clock,
    input reset_n,
    input data_in,
    input sel,
    output serial_out,
    output done,
    output serial_clk
);

    reg [63:0] data_reg;
    reg [63:0] serial_data;
    reg [63:0] tx_buffer;
    reg [63:0] tx_buffer_sel;
    reg [63:0] tx_buffer_data;
    reg [63:0] tx_buffer_ptr;
    reg [63:0] tx_buffer_valid;
    reg [63:0] tx_buffer_done;

    case (sel)
        3'b000: begin
            serial_out = 64'h0;
            done = 1'b0;
            serial_clk = 1'b0;
        end
        3'b001: begin
            tx_buffer_valid = 1'b1;
            tx_buffer_ptr = 0;
            tx_buffer_done = 1'b0;
            tx_buffer = data_in;
            tx_buffer_sel = 7'h7f;
            tx_buffer_data = data_in;
        end
        3'h010: begin
            tx_buffer_valid = 1'b1;
            tx_buffer_ptr = 0;
            tx_buffer_done = 1'b0;
            tx_buffer = data_in;
            tx_buffer_sel = 15'hff;
            tx_buffer_data = data_in;
        end
        3'h011: begin
            tx_buffer_valid = 1'b1;
            tx_buffer_ptr = 0;
            tx_buffer_done = 1'b0;
            tx_buffer = data_in;
            tx_buffer_sel = 31'hff;
            tx_buffer_data = data_in;
        end
        3'h012: begin
            tx_buffer_valid = 1'b1;
            tx_buffer_ptr = 0;
            tx_buffer_done = 1'b0;
            tx_buffer = data_in;
            tx_buffer_sel = 63'hff;
            tx_buffer_data = data_in;
        end
        default: begin
            serial_out = 64'h0;
            done = 1'b0;
            serial_clk = 1'b0;
        end

    // Tx logic
    always clockposededge #1 (posedge clock) begin
        if (reset_n) begin
            data_reg = 64'h0;
            serial_data = 64'h0;
            tx_buffer = 64'h0;
            tx_buffer_ptr = 0;
            tx_buffer_valid = 1'b0;
            tx_buffer_done = 1'b0;
        end
        else if (tx_buffer_valid) begin
            serial_data = data_reg;
            tx_buffer_valid = 1'b0;
            tx_buffer_ptr = (tx_buffer_ptr + 1) % 64;
        end
        else if (tx_buffer_ptr >= 64) begin
            tx_buffer_valid = 1'b1;
            tx_buffer_ptr = 0;
            tx_buffer_done = 1'b1;
            data_reg = tx_buffer_data;
        end

        if (tx_buffer_done) begin
            serial_out = data_reg;
            done = 1'b1;
            serial_clk = 1'b1;
        end
    end

    // Rx logic
    reg [63:0] rx_buffer;
    reg [63:0] rx_buffer_ptr;
    reg [63:0] rx_buffer_valid;
    reg [63:0] rx_buffer_done;

    case (sel)
        3'b000: begin
            rx_buffer = 64'h0;
            rx_buffer_ptr = 0;
            rx_buffer_valid = 1'b0;
            rx_buffer_done = 1'b0;
        end
        3'b001: begin
            rx_buffer = 64'h0;
            rx_buffer_ptr = 0;
            rx_buffer_valid = 1'b0;
            rx_buffer_done = 1'b0;
        end
        3'h010: begin
            rx_buffer = 64'h0;
            rx_buffer_ptr = 0;
            rx_buffer_valid = 1'b0;
            rx_buffer_done = 1'b0;
        end
        3'h011: begin
            rx_buffer = 64'h0;
            rx_buffer_ptr = 0;
            rx_buffer_valid = 1'b0;
            rx_buffer_done = 1'b0;
        end
        3'h012: begin
            rx_buffer = 64'h0;
            rx_buffer_ptr = 0;
            rx_buffer_valid = 1'b0;
            rx_buffer_done = 1'b0;
        end
        default: begin
            rx_buffer = 64'h0;
            rx_buffer_ptr = 0;
            rx_buffer_valid = 1'b0;
            rx_buffer_done = 1'b0;
        end

    // Rx logic
    always clockposededge #1 (posedge clock) begin
        if (reset_n) begin
            rx_buffer = 64'h0;
            rx_buffer_ptr = 0;
            rx_buffer_valid = 1'b0;
            rx_buffer_done = 1'b0;
        end
        else if (rx_buffer_valid) begin
            rx_buffer_valid = 1'b0;
            rx_buffer_ptr = (rx_buffer_ptr + 1) % 64;
            rx_buffer[rx_buffer_ptr] = serial_data;
        end
        else if (rx_buffer_ptr >= 64) begin
            rx_buffer_valid = 1'b1;
            rx_buffer_ptr = 0;
            rx_buffer_done = 1'b1;
            data_reg = rx_buffer;
        end

        if (rx_buffer_done) begin
            data_out = data_reg;
            done = 1'b1;
        end
    end

endmodule

module sync_serial_communication_top(
    input clk,                     // Clock signal
    input reset_n,                 // Active low reset signal
    input [2:0] sel,               // Selection signal for TX block
    input [63:0] data_in,          // 64-bit data input for TX block
    output [63:0] data_out,        // 64-bit data output from RX block
    output done                    // Done signal indicating completion
);

// Internal signals
wire tx_out;                       // Serial data output from TX block
wire tx_done;                      // Done signal from TX block
wire serial_clk_in;                // Serial clock generated by TX block

// Instantiate the TX block
tx_block uut_tx_block (
    .clk(clk),                     // Clock input to TX block
    .reset_n(reset_n),             // Reset input to TX block
    .data_in(data_in),             // 64-bit data input to TX block
    .sel(sel),                     // Selection signal to TX block
    .serial_out(tx_out),           // Serial data output from TX block
    .done(tx_done),                // Done signal from TX block
    .serial_clk(serial_clk_in)     // Serial clock output from TX block
);

// Instantiate the RX block
rx_block uut_rx_block (
    .clk(clk),                     // Clock input to RX block
    .serial_clk(serial_clk_in),    // Serial clock input to RX block
    .reset_n(reset_n),             // Reset input to RX block
    .sel(sel),                     // Selection signal to RX block
    .data_in(tx_out),              // Serial data input to RX block
    .data_out(data_out),           // 64-bit data output from RX block
    .done(done)                    // Done signal from RX block
);

endmodule

///// tx_block
module tx_block(
    input clk,               // Clock input
    input reset_n,           // Active-low reset input
    input [63:0] data_in,    // 64-bit parallel data input
    input [2:0] sel,         // Selection input to choose data width
    output reg serial_out,   // Serial data output
    output reg done,         // Done signal indicating completion of transmission
    output serial_clk        // Clock for serial data transmission
);

// Internal registers
reg [63:0] data_reg;         // Register to hold the data being transmitted
reg [6:0] bit_count;         // Counter to track number of bits to transmit
reg [6:0] reg_count;         // Register for counting bits for serial clock control
reg [6:0] temp_reg_count;    // Temporary register to track reg_count

// Sequential block for state control and data selection
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        data_reg     <= 64'h0;
        bit_count    <= 7'h0;
        reg_count    <= 7'h0;
    else begin
        if (done == 1'b1) begin
            case (sel)
                3'b000: begin
                    data_reg  <= 64'h0;
                    bit_count <= 7'd0;
                end
                3'b001: begin
                    data_reg  <= {56'h0, data_in[7:0]};
                    bit_count <= 7'd7;
                end
                3'b010: begin
                    data_reg  <= {48'h0, data_in[15:0]};
                    bit_count <= 7'd15;
                end
                3'b011: begin
                    data_reg  <= {32'h0, data_in[31:0]};
                    bit_count <= 7'd31;
                end
                3'b100: begin
                    data_reg  <= data_in[63:0];
                    bit_count <= 7'd63;
                end
                default: begin
                    data_reg  <= 64'h0;
                    bit_count <= 7'h0;
                end
            endcase
        end else if (bit_count > 7'h0) begin
            data_reg   <= data_reg >> 1;
            bit_count  <= bit_count - 1'b1;
        end
        reg_count <= bit_count;
    end
end

// Generate serial clock based on reg_count
`ifdef SIMULATION
assign  #1 serial_clk = (reg_count != 7'd0) ? (clk && (temp_reg_count != 7'd0)) : 0;
`else
assign serial_clk = (reg_count != 7'd0) ? (clk && (temp_reg_count != 7'd0)) : 0;
`endif

// Sequential logic to drive the serial_out signal based on reg_count and bit_count
always @(posedge clk or negedge reset_n) begin
    if (reg_count > 7'h0 || bit_count > 7'h0) begin
        serial_out <= data_reg[0];
    end
end

// Set the done signal when transmission is complete (bit_count reaches zero)
always@(posedge clk or negedge reset_n) begin
    if (bit_count == 7'h0) begin
        done <= 1'b1;
    end
end
endmodule

///// rx_block
module rx_block(
    input wire clk,   // clock input
    input wire reset_n, // Active-low reset
    input wire data_in, // Serial input data
    input wire serial_clk, // Clock signal for serial data
    input wire [2:0] sel, // Selection output to choose data width
    output reg done,   // Done signal to indicate data reception complete
    output reg [63:0] data_out // Parallel output data after serial operation
);

// Internal registers
reg [63:0] data_reg;    // Register to hold incoming serial data
reg [7:0] bit_count;    // Counter for the number of bits received

// Sequential logic block to capture serial data on the rising edge of serial_clk
always @(posedge serial_clk or negedge reset_n) begin
    if (!reset_n) begin
        data_reg <= 64'h0;
        bit_count <= 8'd0;
    else begin
        if (done == 1'b1) begin
            bit_count <= 8'd0;
            data_reg <= 64'h0;
        else begin
            bit_count <= bit_count + 1'b1;
            data_reg[bit_count] <= data_in;
        end
    end
end

// Sequential logic block to monitor the completion of data reception and update outputs
always@(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        done <= 1'b0;
        data_out <= 64'h0;
    else if (bit_count >= 8'd0) begin
        done <= 1'b1;
        case(sel)
            3'b000: begin
                data_out <= 64'h0;
            end
            3'b001: begin
                data_out <= {56'h0, data_reg};
            end
            3'b010: begin
                data_out <= {48'h0, data_reg};
            end
            3'b011: begin
                data_out <= {32'h0, data_reg};
            end
            3'b100: begin
                data_out <= data_reg;
            end
            default: begin
                data_out <= 64'h0;
            end
        end
    end
end
endmodule

output.rtl/thermostat.v:
module thermostat(
    input wire [5:0] i_temp_feedback,
    input wire i_fan_on,
    input wire i_enable,
    input wire i_fault,
    input wire i_rst,
    output wire [2:0] o_state,
    output wire o_heater_full,
    output wire o_heater_medium,
    output wire o_heater_low,
    output wire o_aircon_full,
    output wire o_aircon_medium,
    output wire o_aircon_low,
    output wire o_fan
);

    // Reset override
    if (i_rst) begin
        o_state = 3'b000;
        o_heater_full = 0;
        o_heater_medium = 0;
        o_heater_low = 0;
        o_aircon_full = 0;
        o_aircon_medium = 0;
        o_aircon_low = 0;
        o_fan = 0;
        return;
    end

    // Fault override
    if (i_fault) begin
        o_state = 3'b000;
        o_heater_full = 0;
        o_heater_medium = 0;
        o_heater_low = 0;
        o_aircon_full = 0;
        o_aircon_medium = 0;
        o_aircon_low = 0;
        o_fan = 0;
        return;
    end

    // Enable override
    if (i_enable) begin
        o_state = o_state; // FSM state remains same
        o_heater_full = 0;
        o_heater_medium = 0;
        o_heater_low = 0;
        o_aircon_full = 0;
        o_aircon_medium = 0;
        o_aircon_low = 0;
    end

    // Default state transitions
    case (i_temp_feedback)
        6'b111000: // full hot
            o_state = 3'b110;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = i_fan_on || (o_state == 3'b110);
            break;
        6'b110100: // medium hot
            o_state = 3'b101;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = i_fan_on || (o_state == 3'b101);
            break;
        6'b101000: // low hot
            o_state = 3'b100;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = i_fan_on || (o_state == 3'b100);
            break;
        6'b011000: // full cold
            o_state = 3'b001;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = i_fan_on || (o_state == 3'b001);
            break;
        6'b010100: // medium cold
            o_state = 3'b010;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = i_fan_on || (o_state == 3'b010);
            break;
        6'b001000: // low cold
            o_state = 3'b011;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = i_fan_on || (o_state == 3'b011);
            break;
        default:
            o_state = 3'b000;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = i_fan_on || (o_state == 3'b000);
            break;
    endcase

    // Generate outputs based on state
    generate
        if (o_state == 3'b000) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
        else if (o_state == 3'b001) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 1;
