            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 1;
            o_aircon_low = 0;
        end else if (o_state == 3'b011) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 1;
            o_aircon_low = 1;
        end else if (o_state == 3'b100) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 1;
            o_aircon_medium = 0;
            o_aircon_low = 0;
        end else if (o_state == 3'b101) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 1;
            o_aircon_medium = 1;
            o_aircon_low = 0;
        end else if (o_state == 3'b110) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 1;
            o_aircon_medium = 0;
            o_aircon_low = 1;
