module ttc_counter_lite (
    input clock,
    input reset,
    input axi_addr,
    input axi_wdata,
    input axi_write_en,
    input axi_read_en,
    output reg count,
    output reg axi_rdata,
    output reg interrupt,
    output reg status
);

    // Control register: [enable, interval_mode, interrupt_enable]
    reg control[32];

    // Match value register
    reg match_value[32];
    // Reload value register
    reg reload_value[32];
    // Status register
    reg status_reg[32];

    // Always reset
    always_comb begin
        if (reset) begin
            count = 0;
            match_value = 0;
            reload_value = 0;
            status_reg = 0;
            // disable all signals
            axi_rdata = 0;
            interrupt = 0;
        end
    end

    // Counter increment logic
    always clock begin
        if (reset) return;

        if (control[0] && !control[1] && !control[2]) begin
            count = count + 1;
            // Check if match value is set
            if (count == match_value) begin
                // Set match flag
                match_value = count;
                // Stop counting in non-interval mode
                control[1] = 1;
            end
        end
    end

    // Reload value logic
    always clock begin
        if (control[1] && count == reload_value) begin
            count = reload_value;
        end
    end

    // Match detection
    always clock begin
        if (count == match_value) begin
            // Set match flag
            match_value = count;
        end
    end

    // Interrupt generation
    always clock begin
        if (control[2] && match_value == match_value && status_reg[0]) begin
            interrupt = 1;
        end
    end

    // Status register
    always clock begin
        if (interrupt) begin
            status_reg[0] = 1;
        end
        if (reset) begin
            status_reg = 0;
        end
    end

output.rtl/unpack_one_hot.v:
module unpack_one_hot(
    input sign,
    input size,
    input [2:0] one_hot_selector,
    input [255:0] source_reg,
    output [511:0] destination_reg
);
    parameter i;
    integer i;
    integer chunk_size;
    integer src_offset;
    integer dst_offset;

    always begin
        destination_reg = 0;

        case (one_hot_selector)
        // 3'b001: unpack each bit into 8-bit
        3'b001:
            chunk_size = 1;
            src_offset = 0;
            for (i = 0; i < 256; i = i + chunk_size) {
                // unpack 1 bit into 8-bit
                byte b = (source_reg[src_offset] >> 7 - src_offset) & 1;
                if (sign) {
                    b = b ? (8'b11111111) : (8'b00000000);
                } else {
                    b = b ? (8'b00000000) : (8'b11111111);
                }
                destination_reg[dst_offset:dst_offset+7] = b;
                src_offset += chunk_size;
                dst_offset += chunk_size;
            }
            break;
        // 3'b010: unpack each 2-bit segment into 8-bit
        3'b010:
            chunk_size = 2;
            src_offset = 0;
            for (i = 0; i < 256; i = i + chunk_size) {
                // unpack 2 bits into 8-bit
                byte b = (source_reg[src_offset + 1] >> 7 - src_offset) & 2;
                if (sign) {
                    b = b ? (8'b11111111) : (8'b00000000);
                } else {
                    b = b ? (8'b00000000) : (8'b11111111);
                }
                destination_reg[dst_offset:dst_offset+7] = b;
                src_offset += chunk_size;
                dst_offset += chunk_size;
            }
            break;
        // 3'b100: size-dependent
        3'b100:
            if (size) {
                // unpack 8-bit into 16-bit
                byte src8 = source_reg[src_offset:src_offset+7];
                if (sign) {
                    src8 = src8 ? (16'b10_0000_0000_0000) : (16'b00_0000_0000_0000);
                } else {
                    src8 = src8 ? (16'b00_0000_0000_0000) : (16'b11_1111_1111_1111);
                }
                destination_reg[dst_offset:dst_offset+15] = src8;
                src_offset += 8;
                dst_offset += 16;
            } else {
                // unpack 4-bit into 8-bit
                byte src4 = source_reg[src_offset:src_offset+3];
                if (sign) {
                    src4 = src4 ? (8'b1111_0000) : (8'b0000_1111);
                } else {
                    src4 = src4 ? (8'b0000_1111) : (8'b1111_0000);
                }
                destination_reg[dst_offset:dst_offset+7] = src4;
                src_offset += 4;
                dst_offset += 8;
            }
            break;
        default:
            // assign source_reg directly to destination_reg
            destination_reg = source_reg;
            break;
        endcase
    end
endmodule

output.rtl/vending_machine.sv:
// State array
state [
    // IDLE
    idle,
    // ITEM_SELECTION
    item_selection,
    // PAYMENT_VALIDATION
    payment_validation,
    // DISPENSING_ITEM
    dispensing_item,
    // RETURN_CHANGE
    return_change,
    // RETURN_MONEY
    return_money
] fsm;

// State variables
reg idle_state = idle;
reg item_selection_state = item_selection;
reg payment_validation_state = payment_validation;
reg dispensing_item_state = dispensing_item;
reg return_change_state = return_change;
reg return_money_state = return_money;

// State transition table
always @* begin
    case (idle_state)
        item_button & !rst => idle_state = item_selection;
        default => idle_state = idle;
    endcase

    case (item_selection_state)
        item_selected & !rst => idle_state = payment_validation;
        cancel & !rst => idle_state = return_money;
        default => idle_state = idle;
    endcase

    case (payment_validation_state)
        coin_input & !rst => 
            if (item_price >= 4'b00001 & item_price <= 4'b00100) 
                if (coins_accumulated >= item_price) 
                    idle_state = dispensing_item;
                else 
                    error = 1;
                    idle_state = return_money;
            else 
                error = 1;
                idle_state = return_money;
        default => idle_state = idle;
    endcase

    case (dispensing_item_state)
        return_change & !rst => idle_state = return_change;
        dispense_item & !rst => idle_state = idle;
        default => idle_state = idle;
    endcase

    case (return_change_state)
        return_money & !rst => idle_state = return_money;
        default => idle_state = idle;
    endcase

    case (return_money_state)
        return_money & !rst => idle_state = idle;
        default => idle_state = idle;
    endcase
endsys

output.rtl/vga_controller.sv:
module vga_controller(
    input clock,
    input reset,
    input color_in,
    output hsync,
    output vsync,
    output red,
    output green,
    output blue,
    output next_x,
    output next_y,
    output blank
);

    // Horizontal State Machine
    state h_state, v_state;
    reg [9:0] h_counter, v_counter;

    // State Definitions
    // Horizontal States:
    // 0 - Active
    // 1 - Front Porch
    // 2 - Sync Pulse
    // 3 - Back Porch
    // Vertical States:
    // 0 - Active
    // 1 - Front Porch
    // 2 - Sync Pulse
    // 3 - Back Porch

    always_ff (posedge clock) begin
        case(reset)
            1: h_state = 0; v_state = 0; h_counter = 0; v_counter = 0; line_done = 0;
        endcase

        case(h_state)
            0: 
                if (line_done) begin
                    h_counter = 0;
                    h_state = 1;
                end
            1: 
                h_counter = h_counter + 1;
                if (h_counter == H_ACTIVE) begin
                    h_counter = 0;
                    h_state = 2;
                    vsync = 1;
                end
            2: 
                if (h_counter == H_FRONT) begin
                    h_counter = 0;
                    h_state = 3;
                    vsync = 0;
                end
            3: 
                if (h_counter == H_PULSE) begin
                    h_counter = 0;
                    h_state = 4;
                    vsync = 1;
                end
            4: 
                if (h_counter == H_BACK) begin
                    h_counter = 0;
                    h_state = 0;
                    vsync = 0;
                end
        endcase

        case(v_state)
            0: 
                if (vsync == 1) begin
                    v_counter = v_counter + 1;
                    if (v_counter == V_ACTIVE) begin
                        v_counter = 0;
                        v_state = 1;
                        hsync = 1;
                    end
                end
            1: 
                v_counter = v_counter + 1;
                if (v_counter == V_FRONT) begin
                    v_counter = 0;
                    v_state = 2;
                    hsync = 0;
                end
            2: 
                if (v_counter == V_PULSE) begin
                    v_counter = 0;
                    v_state = 3;
                    hsync = 1;
                end
            3: 
                if (v_counter == V_BACK) begin
                    v_counter = 0;
                    v_state = 0;
                    hsync = 0;
                end
        endcase
    end

    // Color Control
    always clock begin
        if (hsync == 1 || vsync == 1) begin
            red = (color_in[7:5] << 3) | (3'd0);
            green = (color_in[4:2] << 2) | (5'd0);
            blue = (color_in[1:0] << 1) | (6'd0);
        else begin
            red = 3'd0;
            green = 5'd0;
            blue = 6'd0;
        end
    end

    // Blank Signal
    blank = (hsync & vsync);

    // Synchronization Signal
    sync = 0;

    // Pixel Position Tracking
    next_x = h_counter;
    next_y = v_counter;

    // Active Mode Indicator
    line_done = 0;

    // Horizontal and Vertical Timing Parameters
    const H_ACTIVE = 640;
    const H_FRONT = 16;
    const H_PULSE = 96;
    const H_BACK = 48;
    const V_ACTIVE = 480;
    const V_FRONT = 10;
    const V_PULSE = 2;
    const V_BACK = 33;

endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    h_counter ++; 
                    hsync <= HIGH;
                    if (h_counter == H_ACTIVE-1) begin
                        h_state <= H_FRONT_STATE;
                    end
                end
                H_FRONT_STATE: begin
                    h_counter ++; 
                    if (h_counter == H_FRONT-1) begin
                        h_state <= H_PULSE_STATE;
                    end
                end
                H_PULSE_STATE: begin
                    hsync <= LOW;
                    h_counter ++; 
                    if (h_counter == H_PULSE-1) begin
                        h_state <= H_BACK_STATE;
                    end
                end
                H_BACK_STATE: begin
                    hsync <= HIGH;
                    h_counter ++; 
                    if (h_counter == H_BACK-1) begin
                        h_state <= H_ACTIVE_STATE;
                        line_done <= HIGH;
                    end
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    v_counter ++; 
                    vsync <= HIGH;
                    if (v_counter == V_ACTIVE-1) begin
                        v_state <= V_FRONT_STATE;
                    end
                end
                V_FRONT_STATE: begin
                    v_counter ++; 
                    if (v_counter == V_FRONT-1) begin
                        v_state <= V_PULSE_STATE;
                    end
                end
                V_PULSE_STATE: begin
                    vsync <= LOW;
                    v_counter ++; 
                    if (v_counter == V_PULSE-1) begin
                        v_state <= V_BACK_STATE;
                    end
                end
                V_BACK_STATE: begin
                    v_counter ++; 
                    if (v_counter == V_BACK-1) begin
                        v_state <= V_ACTIVE_STATE;
                    end
                end
            endcase
        end
    end


    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

    // RGB Signal Handling
    always_ff @(posedge clock or posedge reset) begin
        if (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) begin
            red <= color_in;
            green <= color_in;
            blue <= color_in;
        else begin
            red <= 10'd0;
            green <= 10'd0;
            blue <= 10'd0;
        end
    end
;

    assign line_done = (h_state == H_BACK_STATE) ? 1'b1 : 1'b0;
;

