module write_buffer_merge #(
  parameter INPUT_DATA_WIDTH  = 32,                                     // Width of input data
  parameter INPUT_ADDR_WIDTH  = 16,                                     // Width of input address
  parameter BUFFER_DEPTH      = 8,                                      // Depth of the write buffer
  parameter OUTPUT_DATA_WIDTH = INPUT_DATA_WIDTH * BUFFER_DEPTH,        // Width of merged output data
  parameter OUTPUT_ADDR_WIDTH = INPUT_ADDR_WIDTH - $clog2(BUFFER_DEPTH) // Width of merged output address
) (
  input  logic                         clk,          // Clock signal
  input  logic         srst,         // Synchronous reset (active high)
  input  logic  wr_en_in,     // Write enable input
  input  logic [INPUT_ADDR_WIDTH-1:0] wr_addr_in,   // Write address input
  input  logic [INPUT_DATA_WIDTH-1:0] wr_data_in,   // Write data input
  output logic  wr_en_out,    // Write enable output
  output logic [OUTPUT_ADDR_WIDTH-1:0] wr_addr_out,  // Write address output
  output logic [OUTPUT_DATA_WIDTH-1:0] wr_data_out   // Write data output
);

  // Internal signals for buffer tracking and management
  logic [$clog2(BUFFER_DEPTH)-1:0] write_count;     // Counter for the number of writes in the buffer
  logic [OUTPUT_ADDR_WIDTH-1:0] base_addr;         // Base address for the merged writes
  logic [OUTPUT_DATA_WIDTH-1:0] merged_data;       // Buffer to hold merged data
  logic write_complete;                           // Signal to indicate that the buffer is full and ready to output

  generate
    if (BUFFER_DEPTH > 1) begin
      // Write count logic: Counts the number of writes in the buffer
      always_ff @(posedge clk) begin
        if (srst)
          write_count <= '0;
        else if (wr_en_in)
          write_count <= write_count + 1;  // Increment count on write enable
      end

      // Base address logic: Captures the address of the first write in the buffer
      always_ff @(posedge clk) begin
        if (srst)
          base_addr <= '0;
        else if (!srst && !wr_en_in && write_count == 0)
          base_addr <= (wr_addr_in >> $clog2(BUFFER_DEPTH));
      end

      // Merged data logic: Concatenates incoming data into the buffer
      always_ff @(posedge clk) begin
        if (srst)
          merged_data <= '0;
        else if (wr_en_in)
          merged_data <= (merged_data >> INPUT_DATA_WIDTH) | wr_data_in;
      end

      // Write completion logic: Indicates when the buffer is full
      always_ff @(posedge clk) begin
        if (srst)
          write_complete <= 1'b0;
        else if (write_count == (BUFFER_DEPTH - 1) && wr_en_in)
          write_complete <= 1'b1;  // Assert completion when buffer is full
        else
          write_complete <= 1'b0;
      end

      // Output logic for BUFFER_DEPTH > 1
      always_ff @(posedge clk) begin
        if (write_complete) begin
          // Output valid data for two clock cycles
          wr_en_out <= 1;
          wr_addr_out <= base_addr;
          wr_data_out <= merged_data;
        end else
          // Hold outputs until valid data is ready
          wr_en_out <= 0;
          wr_addr_out <= 0;
          wr_data_out <= 0;
      end
    else begin
      // Pass-through logic for BUFFER_DEPTH = 1
      always_ff @(posedge clk) begin
        if (srst)
          wr_en_out <= 0;
          wr_addr_out <= 0;
          wr_data_out <= 0;
        else
          wr_en_out <= wr_en_in;
          wr_addr_out <= wr_addr_in;
          wr_data_out <= wr_data_in;
        end
      end
    end
  endgenerate

endmodule

input.rtl/ddm_cache.sv:
module ddm_cache (
  input  logic        clk,           // Posedge clock
  input  logic        rst_n,         // Asynchronous Negedge reset
  input  logic [31:0] cpu_addr,      // Memory address emitted by the CPU
  input  logic [31:0] cpu_dout,      // Data emitted by CPU
  input  logic        cpu_strobe,    // CPU status signal to Cache to indicate it is going to perform a read or write operation
  input  logic        cpu_rw,        // cpu_rw == 1, Memory Write Operation ; cpu_rw == 0 , Memory Read Operation
  input  logic        uncached,      // uncached == 1 , IO port is accessed ; uncached == 0, Memory is accessed
  input  logic [31:0] mem_dout,      // Data emitted by memory
  input  logic        mem_ready,     // Memory is ready with the read data
  output logic [31:0] cpu_din,       // CPU Data coming from Memory through Cache
  output logic [31:0] mem_din,       // Memory Data coming from CPU through Cache
  output logic        cpu_ready,     // Cache is ready with data to be provided to CPU
  output logic        mem_strobe,    // Cache Status signal to Memory to indicate it is going to perform a read or write operation
  output logic        mem_rw,        // mem_rw == 1, Memory Write Operation ; mem_rw == 0 , Memory Read Operation
  output logic [31:0] mem_addr,      // Memory address to be accessed, emitted by the Cache
  output logic        cache_hit,     // Indicates a memory location is available in the cache
  output logic        cache_miss,    // Indicates a memory location is not available in the cache
  output logic [31:0] d_data_dout     // Data at a cache index
);

  logic         d_valid [0:63];
  logic [23:0]  d_tags  [0:63];
  logic [31:0]  d_data  [0:63];

  logic [23:0] tag;
  logic [5:0]  index;

  logic [31:0] cache_din;   
  logic        cache_write; 
  logic [23:0] d_tag_out;
  logic        valid;
  logic [31:0] cache_dout;

  integer i;

  assign tag   = cpu_addr[31:8];
  assign index = cpu_addr[7:2]; 
  assign cache_write = ~uncached & (cpu_rw | cache_miss & mem_ready); 

  always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
          for (i = 0; i < 64; i = i + 1) begin
              d_valid[i] <= 0;
          end
      end else if (cache_write) begin
          d_valid[index] = 1;  
      end
  end

  assign cache_din = cpu_rw ? cpu_dout : mem_dout;
  always_ff@(posedge clk) begin
       if(cache_write) begin
            d_tags [index] <= tag;
            d_data [index] = cache_din;
       end else begin
             d_tags [index] <= d_tags[index] + 32'd0;
             d_data [index] = d_data[index]  + 32'd0;
       end
  end  

  assign valid          = d_valid[index];
  assign d_tag_out      = d_tags [index];
  assign cache_dout     = d_data [index];

  assign cache_hit      = cpu_strobe & valid & (d_tag_out == tag);
  assign cache_miss     = cpu_strobe & (!valid | (d_tag_out != tag)); 
  assign mem_din        = cpu_dout;
  assign mem_addr       = cpu_addr;
  assign mem_rw         = cpu_rw;
  assign mem_strobe     = cpu_strobe | cache_miss;
  assign cpu_ready      = ~cpu_rw & cache_hit | (cache_miss | cpu_rw) & mem_ready; 
  assign cpu_din        = cache_hit ? cache_dout : mem_dout;
  assign d_data_dout    = cache_dout;
endmodule

